w-full pl-8 pr-3 py-2 rounded-xl bg-white/[0.04] border border-white/[0.08] text-sm text-slate-300 placeholder-slate-600 focus:outline-none focus:border-[#10B981]/30 focus:bg-white/[0.06] transition-all"
                    />
