/**
 * POST /api/ai/create-trip-from-text
 *
 * Extracts trip details from natural language and creates a Trip.
 */

import { NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import {
    successResponse,
    errorResponse,
    unauthorizedResponse,
} from "@/lib/api/response";
import { getAuthContext, validateBody } from "@/lib/api/request";
import { runWithRequestContext } from "@/lib/requestContext";
import { logError } from "@/infrastructure/logger";
import { checkRateLimit } from "@/security/rateLimiter";
import { formatErrorResponse } from "@/lib/errors";
import { serializeTrip, type TripDTO } from "@/lib/services/trips";
import { getDestinationImage } from "@/lib/services/image.service";
import { extractTripFromText } from "@/services/ai/create-trip-from-text.service";
import { CreateTripFromTextInputSchema } from "@/lib/ai/schemas";
import { getTravelPreferenceContext } from "@/memory/contextStore";

export async function POST(req: NextRequest) {
    return runWithRequestContext(req, async () => {
        const auth = getAuthContext(req);
        if (!auth) return unauthorizedResponse();

        const validation = await validateBody(req, CreateTripFromTextInputSchema);
        if (!validation.ok) return validation.response;

        const { text } = validation.data;

        try {
            await checkRateLimit(`ai:${auth.user.sub}:create-trip`);

            const dnaContext = await getTravelPreferenceContext(auth.user.sub);
            const extracted = await extractTripFromText(text, dnaContext || undefined);

            const defaultStart = new Date();
            defaultStart.setDate(defaultStart.getDate() + 30);
            const defaultEnd = new Date(defaultStart);
            defaultEnd.setDate(defaultEnd.getDate() + 7);
            const startDate = extracted.startDate ?? defaultStart.toISOString().slice(0, 10);
            const endDate   = extracted.endDate   ?? defaultEnd.toISOString().slice(0, 10);

            let imageUrl: string | null = null;
            try {
                imageUrl = await getDestinationImage(extracted.destination);
            } catch {
                imageUrl = null;
            }

            const trip = await prisma.trip.create({
                data: {
                    userId: auth.user.sub,
                    destination: extracted.destination,
                    startDate: new Date(startDate),
                    endDate: new Date(endDate),
                    budgetTotal: extracted.budget?.total ?? 0,
                    budgetCurrency: extracted.budget?.currency ?? "USD",
                    style: extracted.style ?? undefined,
                    imageUrl: imageUrl ?? undefined,
                },
            });

            return successResponse<TripDTO>(serializeTrip(trip), 201);
        } catch (err) {
            logError("[POST /api/ai/create-trip-from-text] Error", err);
            return formatErrorResponse(err);
        }
    });
}

/**
 * POST /api/ai/extract-trip-params
 *
 * Extracts trip details from natural language and returns them (with an image URL)
 * for user confirmation before creating the actual trip.
 */

import { NextRequest, NextResponse } from "next/server";
import { unauthorizedResponse } from "@/lib/api/response";
import { getAuthContext, validateBody } from "@/lib/api/request";
import { runWithRequestContext } from "@/lib/requestContext";
import { logError } from "@/infrastructure/logger";
import { checkRateLimit } from "@/security/rateLimiter";
import { formatErrorResponse } from "@/lib/errors";
import { getDestinationImage } from "@/lib/services/image.service";
import { extractTripFromText } from "@/services/ai/create-trip-from-text.service";
import { CreateTripFromTextInputSchema, type CreateTripFromTextOutput } from "@/lib/ai/schemas";
import { getTravelPreferenceContext } from "@/memory/contextStore";

export async function POST(req: NextRequest) {
    return runWithRequestContext(req, async () => {
        const auth = getAuthContext(req);
        if (!auth) return unauthorizedResponse();

        const validation = await validateBody(req, CreateTripFromTextInputSchema);
        if (!validation.ok) return validation.response;

        const { text } = validation.data;

        try {
            await checkRateLimit(`ai:${auth.user.sub}:extract-trip`);

            const dnaContext = await getTravelPreferenceContext(auth.user.sub);
            const extracted = await extractTripFromText(text, dnaContext || undefined);

            const defaultStart = new Date();
            defaultStart.setDate(defaultStart.getDate() + 30);
            const defaultEnd = new Date(defaultStart);
            defaultEnd.setDate(defaultEnd.getDate() + 7);
            
            const startDate = extracted.startDate ?? defaultStart.toISOString().slice(0, 10);
            const endDate   = extracted.endDate   ?? defaultEnd.toISOString().slice(0, 10);

            let imageUrl: string | null = null;
            try {
                imageUrl = await getDestinationImage(extracted.destination);
            } catch {
                imageUrl = null;
            }

            const responsePayload = {
                destination: extracted.destination,
                startDate,
                endDate,
                budget: extracted.budget,
                style: extracted.style,
                imageUrl,
            };

            return NextResponse.json({ success: true, data: responsePayload }, { status: 200 });
        } catch (err) {
            logError("[POST /api/ai/extract-trip-params] Error", err);
            return formatErrorResponse(err);
        }
    });
}

import { NextRequest, NextResponse } from "next/server";
import { generateCsrfToken } from "@/services/auth/csrf";
import { serializeCsrfCookie } from "@/services/auth/cookies";
import { successResponse } from "@/lib/api/response";
import { runWithRequestContext } from "@/lib/requestContext";

export async function GET(req: NextRequest) {
    return runWithRequestContext(req, async () => {
        const csrfToken = generateCsrfToken();
        const response = successResponse({ csrfToken });
        response.headers.append("Set-Cookie", serializeCsrfCookie(csrfToken));
        return response;
    });
}

/**
 * app/api/auth/refresh/route.ts
 *
 * POST /api/auth/refresh
 *
 * Secure refresh token rotation with reuse detection.
 *
 * Algorithm:
 *  1. Read refresh token from HttpOnly cookie.
 *  2. Verify JWT signature and compute its SHA-256 hash.
 *  3. Load the DB record by hash.
 *  4. If the token is already revoked 鈫?REUSE DETECTED:
 *       Revoke ALL tokens in the same family (session takeover mitigation).
 *  5. If expired, revoke and return 401.
 *  6. Issue a new access + refresh token pair.
 *  7. Revoke the old refresh token, store the new hash, set new cookie.
 *
 * Rate limit: 30 refreshes / 15 min per IP.
 */
import { NextRequest } from "next/server";

import { prisma } from "@/lib/prisma";
import {
    verifyRefreshToken,
    signAccessToken,
    signRefreshToken,
    hashToken,
} from "@/services/auth/tokens";
import { serializeRefreshTokenCookie, clearRefreshTokenCookie, serializeAccessTokenCookie, serializeCsrfCookie } from "@/services/auth/cookies";
import { generateCsrfToken } from "@/services/auth/csrf";
import { rateLimit, REFRESH_RATE_LIMIT } from "@/services/auth/rateLimit";
import { writeAuditLog } from "@/services/auth/audit";
import {
    successResponse,
    unauthorizedResponse,
    rateLimitResponse,
    internalErrorResponse,
} from "@/lib/api/response";
import { getClientIp, getRefreshTokenFromCookie } from "@/lib/api/request";
import { logError } from "@/infrastructure/logger";
import { runWithRequestContext } from "@/lib/requestContext";

export async function POST(req: NextRequest) {
    return runWithRequestContext(req, async () => {
        const ip = getClientIp(req);
        const ua = req.headers.get("user-agent") ?? "unknown";

        // 鈹€鈹€ Rate limit 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        const rl = await rateLimit(`refresh:ip:${ip}`, REFRESH_RATE_LIMIT);
        if (!rl.allowed) {
            await writeAuditLog({ action: "RATE_LIMITED", ipAddress: ip, userAgent: ua });
            return rateLimitResponse(rl.retryAfterMs);
        }

        // 鈹€鈹€ Extract refresh token from cookie 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        const rawToken = getRefreshTokenFromCookie(req);
        if (!rawToken) {
            return unauthorizedResponse("No refresh token provided");
        }

        // 鈹€鈹€ Verify JWT signature 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        let payload;
        try {
            payload = verifyRefreshToken(rawToken);
        } catch (err) {
            // Expired or invalid JWT
            const clearCookie = clearRefreshTokenCookie();
            const response = unauthorizedResponse("Refresh token is invalid or expired");
            response.headers.append("Set-Cookie", clearCookie);
            return response;
        }

        // 鈹€鈹€ Look up token record in DB 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        const tokenHash = hashToken(rawToken);
        const storedToken = await prisma.refreshToken.findUnique({
            where: { tokenHash },
            include: {
                user: {
                    select: {
                        id: true,
                        email: true,
                        name: true,
                        image: true,
                        role: true,
                        isActive: true,
                        hasOnboarded: true,
                        createdAt: true,
                    },
                },
            },
        });

        // 鈹€鈹€ Token not found (was never issued or already rotated) 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        if (!storedToken) {
            // Revoke entire family as a precaution (reuse from unknown token)
            await prisma.refreshToken.updateMany({
                where: { userId: payload.sub, family: payload.family },
                data: { isRevoked: true },
            });
            await writeAuditLog({
                action: "REFRESH_REUSE_DETECTED",
                userId: payload.sub,
                ipAddress: ip,
                userAgent: ua,
                metadata: { family: payload.family, reason: "token_not_found" },
            });
            const clearCookie = clearRefreshTokenCookie();
            const response = unauthorizedResponse("Session compromised. Please log in again.");
            response.headers.append("Set-Cookie", clearCookie);
            return response;
        }

        // 鈹€鈹€ Reuse detection: token was already revoked 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        if (storedToken.isRevoked) {
            // Revoke the entire family 鈥?an attacker may be replaying a stolen token
            await prisma.refreshToken.updateMany({
                where: { family: storedToken.family },
                data: { isRevoked: true },
            });
            await writeAuditLog({
                action: "REFRESH_REUSE_DETECTED",
                userId: storedToken.userId,
                ipAddress: ip,
                userAgent: ua,
                metadata: { tokenId: storedToken.id, family: storedToken.family },
            });
            const clearCookie = clearRefreshTokenCookie();
            const response = unauthorizedResponse("Session compromised. Please log in again.");
            response.headers.append("Set-Cookie", clearCookie);
            return response;
        }

        // 鈹€鈹€ Token expired (belt-and-suspenders: JWT verify should catch this) 鈹€鈹€鈹€鈹€鈹€
        if (storedToken.expiresAt <= new Date()) {
            await prisma.refreshToken.update({
                where: { id: storedToken.id },
                data: { isRevoked: true },
            });
            const clearCookie = clearRefreshTokenCookie();
            const response = unauthorizedResponse("Session expired. Please log in again.");
            response.headers.append("Set-Cookie", clearCookie);
            return response;
        }

        // 鈹€鈹€ Check user is still active 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        if (!storedToken.user.isActive) {
            await prisma.refreshToken.updateMany({
                where: { userId: storedToken.userId },
                data: { isRevoked: true },
            });
            const clearCookie = clearRefreshTokenCookie();
            const response = unauthorizedResponse("Account has been disabled.");
            response.headers.append("Set-Cookie", clearCookie);
            return response;
        }

        // 鈹€鈹€ Issue new token pair 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        // Propagate the existing family so reuse-detection can revoke the entire
        // chain if any token in it is replayed. Rotating the family would break the
        // invariant: replayed old tokens from the same session would orphan new ones.
        const newFamily = storedToken.family;
        const accessToken = signAccessToken({
            sub: storedToken.user.id,
            email: storedToken.user.email,
            role: storedToken.user.role,
        });

        const {
            rawToken: newRawToken,
            tokenHash: newTokenHash,
            expiresAt: newExpiresAt,
        } = signRefreshToken(storedToken.user.id, newFamily);

        // 鈹€鈹€ Atomic: revoke old, store new 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        try {
            await prisma.$transaction([
                prisma.refreshToken.update({
                    where: { id: storedToken.id },
                    data: {
                        isRevoked: true,
                        replacedBy: newTokenHash, // audit trail
                    },
                }),
                prisma.refreshToken.create({
                    data: {
                        userId: storedToken.user.id,
                        tokenHash: newTokenHash,
                        family: newFamily,
                        expiresAt: newExpiresAt,
                        userAgent: ua,
                        ipAddress: ip,
                    },
                }),
            ]);
        } catch (err) {
            logError("[refresh] DB transaction failed", err);
            return internalErrorResponse();
        }

        await writeAuditLog({
            action: "REFRESH",
            userId: storedToken.user.id,
            ipAddress: ip,
            userAgent: ua,
        });

        // 鈹€鈹€ Response 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        const user = {
            id: storedToken.user.id,
            email: storedToken.user.email,
            name: storedToken.user.name,
            image: storedToken.user.image,
            role: storedToken.user.role,
            hasOnboarded: storedToken.user.hasOnboarded,
            createdAt: storedToken.user.createdAt.toISOString(),
        };
        const response = successResponse({ accessToken, user });
        response.headers.append("Set-Cookie", serializeAccessTokenCookie(accessToken));
        response.headers.append("Set-Cookie", serializeRefreshTokenCookie(newRawToken));
        response.headers.append("Set-Cookie", serializeCsrfCookie(generateCsrfToken()));

        return response;
    });
}

/**
 * POST /api/internal/agent/execute
 *
 * Unified internal execution endpoint for the Python LangGraph orchestrator.
 * Each LangGraph node calls this route to run one TypeScript agent step,
 * keeping all agent logic in a single authoritative implementation.
 *
 * Security: requires X-Internal-Agent-Secret header matching
 * INTERNAL_AGENT_SECRET env var. Never expose this route to the browser.
 */

import { NextRequest } from "next/server";
import { z } from "zod";
import { timingSafeEqual } from "crypto";
import { validateBody } from "@/lib/api/request";
import { successResponse, errorResponse, forbiddenResponse } from "@/lib/api/response";
import { logStructured, generateRequestId } from "@/infrastructure/logger";
import { formatErrorResponse } from "@/lib/errors";
import { runWithReplayLog } from "@/services/ai/agentReplayLogger";

import { PlannerAgent } from "@/agents/planner/plannerAgent";
import { ResearchAgent } from "@/agents/research/researchAgent";
import { LogisticsAgent } from "@/agents/logistics/logisticsAgent";
import { BudgetAgent } from "@/agents/budget/budgetAgent";
import { SafetyAgent } from "@/agents/safety/safetyAgent";

// 鈹€鈹€鈹€ Zod schemas for each step payload 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

const PreferencesSchema = z.object({
    budget: z.number().optional(),
    style: z.string().optional(),
    pace: z.string().optional(),
}).optional();

const PlannerPayloadSchema = z.object({
    input: z.string().min(5).max(2000),
});

const ResearchPayloadSchema = z.object({
    destination: z.string(),
    startDate: z.string(),
    endDate: z.string(),
    durationDays: z.number(),
    preferences: PreferencesSchema,
    days: z.array(z.object({ day: z.number(), theme: z.string() })),
});

const ScheduledActivitySchema = z.object({
    name: z.string(),
    type: z.enum(["attraction", "experience", "restaurant"]),
    description: z.string(),
    estimatedCost: z.number().optional(),
    timeSlot: z.enum(["morning", "afternoon", "evening"]),
    lat: z.number().optional(),
    lng: z.number().optional(),
    geoConfidence: z.enum(["high", "medium", "low"]).optional(),
});

const HotelSchema = z.object({
    name: z.string(),
    priceRange: z.enum(["$", "$$", "$$$", "$$$$"]),
    area: z.string(),
    tags: z.array(z.string()),
    rating: z.number().optional(),
    lat: z.number().optional(),
    lng: z.number().optional(),
    geoConfidence: z.enum(["high", "medium", "low"]).optional(),
});

const EnrichedDaySchema = z.object({
    day: z.number(),
    theme: z.string(),
    activities: z.array(z.object({
        name: z.string(),
        type: z.enum(["attraction", "experience", "restaurant"]),
        description: z.string(),
        estimatedCost: z.number().optional(),
        lat: z.number().optional(),
        lng: z.number().optional(),
        geoConfidence: z.enum(["high", "medium", "low"]).optional(),
    })),
});

const LogisticsPayloadSchema = z.object({
    destination: z.string(),
    startDate: z.string(),
    endDate: z.string(),
    durationDays: z.number(),
    preferences: PreferencesSchema,
    days: z.array(EnrichedDaySchema),
    hotels: z.array(HotelSchema),
});

const OptimizedDaySchema = z.object({
    day: z.number(),
    theme: z.string(),
    activities: z.array(ScheduledActivitySchema),
});

const BudgetPayloadSchema = z.object({
    destination: z.string(),
    startDate: z.string(),
    endDate: z.string(),
    durationDays: z.number(),
    preferences: PreferencesSchema,
    days: z.array(OptimizedDaySchema),
    hotels: z.array(HotelSchema),
    selectedHotel: HotelSchema,
});

const SafetyPayloadSchema = BudgetPayloadSchema.extend({
    budget: z.object({
        totalEstimatedCost: z.number(),
        costPerDay: z.array(z.number()).optional(),
        isOverBudget: z.boolean(),
        budgetGap: z.number().optional(),
        suggestions: z.array(z.string()).optional(),
    }),
});

const BodySchema = z.discriminatedUnion("step", [
    z.object({ step: z.literal("planner"),   payload: PlannerPayloadSchema }),
    z.object({ step: z.literal("research"),  payload: ResearchPayloadSchema }),
    z.object({ step: z.literal("logistics"), payload: LogisticsPayloadSchema }),
    z.object({ step: z.literal("budget"),    payload: BudgetPayloadSchema }),
    z.object({ step: z.literal("safety"),    payload: SafetyPayloadSchema }),
]);

// Step index map matches orchestrator convention so replay traces are aligned.
const STEP_INDEX: Record<string, number> = {
    planner:   0,
    research:  1,
    logistics: 2,
    budget:    3,
    safety:    4,
};

// 鈹€鈹€鈹€ Secret validation 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

function isValidInternalSecret(req: NextRequest): boolean {
    const secret = process.env.INTERNAL_AGENT_SECRET;
    if (!secret) {
        // Secret not configured 鈥?block all internal calls in this state.
        return false;
    }
    const header = req.headers.get("x-internal-agent-secret") ?? "";
    // Compare byte buffers, not JS character counts, to handle non-ASCII secrets
    // correctly and to satisfy the equal-length precondition of timingSafeEqual.
    const headerBuf = Buffer.from(header);
    const secretBuf = Buffer.from(secret);
    if (headerBuf.length !== secretBuf.length) return false;
    try {
        return timingSafeEqual(headerBuf, secretBuf);
    } catch {
        return false;
    }
}

// 鈹€鈹€鈹€ In-memory rate limiter 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
//
// Lightweight sliding-window per calling IP. Designed for the internal route
// where the only expected caller is the co-deployed Python service.
// If Redis is available project-wide, the project's existing checkRateLimit
// (src/services/rateLimit) can replace this at any time.

const RATE_LIMIT_WINDOW_MS = 60_000;       // 1 minute window
const RATE_LIMIT_MAX = 200;                // max calls per window per IP

type RateBucket = { count: number; windowStart: number };
const _rateBuckets = new Map<string, RateBucket>();

function isRateLimited(ip: string): boolean {
    const now = Date.now();
    const bucket = _rateBuckets.get(ip);

    if (!bucket || now - bucket.windowStart > RATE_LIMIT_WINDOW_MS) {
        _rateBuckets.set(ip, { count: 1, windowStart: now });
        return false;
    }

    bucket.count += 1;
    if (bucket.count > RATE_LIMIT_MAX) return true;
    return false;
}

// 鈹€鈹€鈹€ Structured error helper 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

function agentErrorResponse(code: string, message: string, stage: string, status = 500) {
    return errorResponse(code, message, status, { stage });
}

// 鈹€鈹€鈹€ Route handler 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

export const runtime = "nodejs";

export async function POST(req: NextRequest) {
    if (!isValidInternalSecret(req)) {
        return forbiddenResponse("Invalid or missing internal agent secret");
    }

    // Lightweight rate limiting 鈥?protects against accidental infinite loops in
    // the Python graph or misconfigured callers.
    const ip =
        req.headers.get("x-real-ip") ??
        req.headers.get("x-forwarded-for")?.split(",")[0].trim() ??
        "internal";
    if (isRateLimited(ip)) {
        return agentErrorResponse("RATE_LIMITED", "Too many internal agent calls", "internal", 429);
    }

    const body = await validateBody(req, BodySchema);
    if (!body.ok) return body.response;

    const { step, payload } = body.data;
    const requestId = req.headers.get("x-request-id") ?? generateRequestId();
    const stepIndex = STEP_INDEX[step];

    logStructured({ layer: "orchestrator", step: "input", requestId, data: { source: "langgraph", calling: step } });

    try {
        let result: unknown;

        if (step === "planner") {
            const agent = new PlannerAgent();
            result = await runWithReplayLog({
                requestId, agentName: "planner", stepIndex,
                input: { promptLength: payload.input.length },
                run: () => agent.run(payload.input, requestId),
                buildOutputSummary: (r) => ({
                    destination: (r as { destination: string }).destination,
                    durationDays: (r as { durationDays: number }).durationDays,
                }),
            });
        } else if (step === "research") {
            const agent = new ResearchAgent();
            result = await runWithReplayLog({
                requestId, agentName: "research", stepIndex,
                input: { destination: payload.destination, durationDays: payload.durationDays },
                run: () => agent.run(payload, requestId),
                buildOutputSummary: (r) => ({
                    days: (r as { days: unknown[] }).days.length,
                    hotels: (r as { hotels: unknown[] }).hotels.length,
                }),
            });
        } else if (step === "logistics") {
            const agent = new LogisticsAgent();
            result = await runWithReplayLog({
                requestId, agentName: "logistics", stepIndex,
                input: { destination: payload.destination, daysCount: payload.days.length },
                run: () => agent.run(payload, requestId),
                buildOutputSummary: (r) => ({
                    selectedHotel: (r as { selectedHotel: { name: string } }).selectedHotel.name,
                }),
            });
        } else if (step === "budget") {
            const agent = new BudgetAgent();
            result = await runWithReplayLog({
                requestId, agentName: "budget", stepIndex,
                input: { selectedHotel: payload.selectedHotel?.name },
                run: () => agent.run(payload, requestId),
                buildOutputSummary: (r) => ({
                    totalEstimatedCost: (r as { budget: { totalEstimatedCost: number; isOverBudget: boolean } }).budget.totalEstimatedCost,
                    isOverBudget: (r as { budget: { totalEstimatedCost: number; isOverBudget: boolean } }).budget.isOverBudget,
                }),
            });
        } else {
            // safety
            const agent = new SafetyAgent();
            result = await runWithReplayLog({
                requestId, agentName: "safety", stepIndex,
                input: { isOverBudget: (payload as { budget: { isOverBudget: boolean } }).budget.isOverBudget },
                run: () => agent.run(payload as Parameters<SafetyAgent["run"]>[0], requestId),
                buildOutputSummary: (r) => ({
                    riskLevel: (r as { safety: { riskLevel: string } }).safety.riskLevel,
                }),
            });
        }

        logStructured({ layer: "orchestrator", step: "output", requestId, data: { source: "langgraph", agent: step } });

        return successResponse({ step, requestId, result });
    } catch (err) {
        logStructured({ layer: "orchestrator", step: "error", requestId, data: { source: "langgraph", agent: step, error: (err as Error).message } });
        return agentErrorResponse(
            "AGENT_EXECUTION_FAILED",
            (err as Error).message ?? "Agent execution failed",
            step,
        );
    }
}

/**
 * app/api/profile/route.ts
 *
 * GET  /api/profile 鈥?Returns the current user (for hydrating auth store).
 * PATCH /api/profile 鈥?Updates the authenticated user's profile (name).
 *
 * Requires valid access token (cookie or Authorization header).
 */

import { NextRequest } from "next/server";
import { z } from "zod";
import { prisma } from "@/lib/prisma";
import { getAuthContext } from "@/lib/api/request";
import { successResponse, errorResponse, validationErrorResponse } from "@/lib/api/response";
import { runWithRequestContext } from "@/lib/requestContext";

export async function GET(req: NextRequest) {
    return runWithRequestContext(req, async () => {
        const auth = getAuthContext(req);
        if (!auth) {
            return errorResponse("UNAUTHORIZED", "You must be signed in to view your profile", 401);
        }

        try {
            const user = await prisma.user.findUnique({
                where: { id: auth.user.sub },
                select: {
                    id: true,
                    email: true,
                    name: true,
                    image: true,
                    role: true,
                    hasOnboarded: true,
                    createdAt: true,
                },
            });

            if (!user) {
                return errorResponse("NOT_FOUND", "User not found", 404);
            }

            return successResponse({
                user: {
                    id: user.id,
                    email: user.email,
                    name: user.name,
                    image: user.image,
                    role: user.role,
                    hasOnboarded: user.hasOnboarded ?? false,
                    createdAt: user.createdAt.toISOString(),
                },
            });
        } catch (err) {
            console.error("[profile] Fetch failed:", err);
            return errorResponse("INTERNAL_ERROR", "Failed to fetch profile", 500);
        }
    });
}

const UpdateProfileSchema = z.object({
    name: z
        .string()
        .min(1, "Name is required")
        .max(100, "Name too long")
        .trim(),
});

export async function PATCH(req: NextRequest) {
    return runWithRequestContext(req, async () => {
    const auth = getAuthContext(req);
    if (!auth) {
        return errorResponse("UNAUTHORIZED", "You must be signed in to update your profile", 401);
    }

    let body: unknown;
    try {
        body = await req.json();
    } catch {
        return errorResponse("BAD_REQUEST", "Request body must be valid JSON", 400);
    }

    const parsed = UpdateProfileSchema.safeParse(body);
    if (!parsed.success) {
        const msg = parsed.error.issues[0]?.message ?? "Invalid input";
        return errorResponse("VALIDATION_ERROR", msg, 400);
    }

    const { name } = parsed.data;

    try {
        const user = await prisma.user.update({
            where: { id: auth.user.sub },
            data: { name },
            select: {
                id: true,
                email: true,
                name: true,
                role: true,
                createdAt: true,
            },
        });

        return successResponse({
            user: {
                id: user.id,
                email: user.email,
                name: user.name,
                role: user.role,
                createdAt: user.createdAt.toISOString(),
            },
        });
    } catch (err) {
        console.error("[profile] Update failed:", err);
        return errorResponse("INTERNAL_ERROR", "Failed to update profile", 500);
    }
    });
}

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { getAuthContext, validateBody } from "@/lib/api/request";
import { successResponse, errorResponse, unauthorizedResponse } from "@/lib/api/response";
import { runWithRequestContext } from "@/lib/requestContext";
import { ItinerarySchema } from "@/lib/ai/schemas";

export async function POST(
    req: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    return runWithRequestContext(req, async () => {
        const auth = getAuthContext(req);
        if (!auth) return unauthorizedResponse();

        const { id } = await params;
        const validation = await validateBody(req, ItinerarySchema);
        if (!validation.ok) return validation.response;

        const updatedItinerary = validation.data;

        try {
            const trip = await prisma.trip.findUnique({ where: { id } });
            if (!trip || trip.userId !== auth.user.sub) return errorResponse("NOT_FOUND", "Trip not found", 404);

            await prisma.$transaction([
                prisma.itinerary.deleteMany({ where: { tripId: id } }),
                prisma.itinerary.create({
                    data: {
                        tripId: id,
                        rawJson: updatedItinerary as unknown as object,
                    },
                }),
                prisma.trip.update({
                    where: { id },
                    data: {
                        budgetTotal: updatedItinerary.totalEstimatedCost.amount,
                        budgetCurrency: updatedItinerary.totalEstimatedCost.currency,
                    },
                }),
            ]);

            return successResponse({ success: true });
        } catch (err) {
            console.error("[itinerary] Update failed:", err);
            return errorResponse("INTERNAL_ERROR", "Failed to update itinerary", 500);
        }
    });
}

/**
 * app/api/trips/route.ts
 *
 * POST /api/trips  鈥?Create a new trip for the authenticated user.
 * GET  /api/trips  鈥?Return all trips for the authenticated user.
 */

import { NextRequest } from "next/server";
import { z } from "zod";
import { prisma } from "@/lib/prisma";
import {
    successResponse,
    errorResponse,
    unauthorizedResponse,
    internalErrorResponse,
} from "@/lib/api/response";
import { getAuthContext, validateBody } from "@/lib/api/request";
import { runWithRequestContext } from "@/lib/requestContext";
import { logError } from "@/infrastructure/logger";
import { serializeTrip, type TripDTO } from "@/lib/services/trips";
import {
    getDestinationImage,
    getDestinationImageCachedOnly,
} from "@/lib/services/image.service";
import { getRedisClient, hasRedisConfig } from "@/lib/redis";

const TTL_ACTIVITY_GLOBAL_SEC = 30 * 24 * 60 * 60;  // 30d
const TTL_ACTIVITY_USER_SEC  = 90 * 24 * 60 * 60;  // 90d

/** Fire-and-forget: record trip creation in Redis Sorted Sets for admin insights. */
function recordTripActivity(userId: string, tripId: string, destination: string): void {
    if (!hasRedisConfig()) return;
    const redis = getRedisClient();
    if (!redis) return;
    const score = Date.now();
    const globalKey = "activity:trips:global";
    const userKey   = `activity:user:${userId}:trips`;
    // Write both sets, set/refresh TTL, trim global to last 10k entries
    void redis.zadd(globalKey, score, `${userId}:${destination}`)
        .then(() => redis.expire(globalKey, TTL_ACTIVITY_GLOBAL_SEC))
        .then(() => redis.zremrangebyrank(globalKey, 0, -10001))
        .catch(() => {});
    void redis.zadd(userKey, score, tripId)
        .then(() => redis.expire(userKey, TTL_ACTIVITY_USER_SEC))
        .then(() => redis.zremrangebyrank(userKey, 0, -1001))  // cap per-user at 1000
        .catch(() => {});
}

const TripStyleEnum = z.enum(["relaxed", "creative", "exciting", "luxury", "budget"]);

const CreateTripSchema = z
    .object({
        destination: z
            .string()
            .min(2, "Destination must be at least 2 characters")
            .max(200, "Destination too long")
            .trim(),
        startDate: z
            .string()
            .regex(/^\d{4}-\d{2}-\d{2}$/, "startDate must be YYYY-MM-DD"),
        endDate: z
            .string()
            .regex(/^\d{4}-\d{2}-\d{2}$/, "endDate must be YYYY-MM-DD"),
        style: TripStyleEnum.optional(),
        budgetTotal: z.number().nonnegative().optional(),
    })
    .refine(
        (d) => new Date(d.endDate) >= new Date(d.startDate),
        { message: "endDate must be on or after startDate", path: ["endDate"] }
    );

// 鈹€鈹€鈹€ POST /api/trips 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

export async function POST(req: NextRequest) {
    return runWithRequestContext(req, async () => {
        const auth = getAuthContext(req);
        if (!auth) return unauthorizedResponse();

        const body = await validateBody(req, CreateTripSchema);
        if (!body.ok) return body.response;

        const { destination, startDate, endDate, style, budgetTotal } = body.data;

        let imageUrl: string | null = null;
        try {
            imageUrl = await getDestinationImage(destination);
        } catch {
            imageUrl = null;
        }

        try {
            const trip = await prisma.trip.create({
                data: {
                    userId: auth.user.sub,
                    destination,
                    startDate: new Date(startDate),
                    endDate: new Date(endDate),
                    style: style ?? undefined,
                    budgetTotal: budgetTotal ?? 0,
                    imageUrl: imageUrl ?? undefined,
                },
            });

            recordTripActivity(auth.user.sub, trip.id, destination);
            return successResponse<TripDTO>(serializeTrip(trip), 201);
        } catch (err) {
            logError("[POST /api/trips] DB error", err);
            return internalErrorResponse();
        }
    });
}

// 鈹€鈹€鈹€ GET /api/trips 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

export const dynamic = "force-dynamic";

export async function GET(req: NextRequest) {
    return runWithRequestContext(req, async () => {
        const auth = getAuthContext(req);
        if (!auth) return unauthorizedResponse();

        const timings: { name: string; dur: number }[] = [];
        const t0 = performance.now();

        try {
            const dbStart = performance.now();
            const trips = await prisma.trip.findMany({
                where: { userId: auth.user.sub },
                include: { itineraries: { orderBy: { createdAt: "desc" }, take: 1 } },
                orderBy: { startDate: "asc" },
            });
            timings.push({ name: "db", dur: Math.round(performance.now() - dbStart) });

            const needsImage = trips.filter((t) => !t.imageUrl);
            const uniqueDestinations = [...new Set(needsImage.map((t) => t.destination))];

            // Fast path: cache-only lookup (Redis only, no Pexels). Target: warm < 500ms.
            const cacheStart = performance.now();
            const cacheResults = await Promise.all(
                uniqueDestinations.map((dest) => getDestinationImageCachedOnly(dest))
            );
            timings.push({ name: "cache", dur: Math.round(performance.now() - cacheStart) });
            const destToImage = new Map<string, string | null>();
            const cacheMissDestinations: string[] = [];
            uniqueDestinations.forEach((dest, i) => {
                const res = cacheResults[i];
                if (res.type === "hit") {
                    destToImage.set(dest, res.url);
                } else {
                    cacheMissDestinations.push(dest);
                }
            });

            // Await image fetches for cache misses so THIS response includes fresh images.
            // DB persistence is fire-and-forget (Redis is the primary cache, DB is secondary).
            if (cacheMissDestinations.length > 0) {
                const requestImageCache = new Map<string, Promise<string | null>>();
                const fetchResults = await Promise.allSettled(
                    cacheMissDestinations.map((dest) =>
                        getDestinationImage(dest, requestImageCache).then((url) => ({ dest, url }))
                    )
                );
                for (const r of fetchResults) {
                    if (r.status === "fulfilled") {
                        destToImage.set(r.value.dest, r.value.url);
                        // Best-effort DB persistence 鈥?fire-and-forget is acceptable here.
                        const tripIds = needsImage
                            .filter((t) => t.destination === r.value.dest)
                            .map((t) => t.id);
                        if (r.value.url && tripIds.length > 0) {
                            void prisma.trip.updateMany({
                                where: { id: { in: tripIds } },
                                data: { imageUrl: r.value.url },
                            });
                        }
                    }
                }
            }

            const dtos: TripDTO[] = trips.map((trip) => {
                const imageUrl =
                    trip.imageUrl ?? destToImage.get(trip.destination) ?? null;
                const rawJson = trip.itineraries[0]?.rawJson;
                return serializeTrip({ ...trip, imageUrl }, [], rawJson);
            });

            timings.push({ name: "total", dur: Math.round(performance.now() - t0) });
            const serverTiming = timings.map((t) => `${t.name};dur=${t.dur}`).join(", ");

            return successResponse<TripDTO[]>(dtos, 200, {
                "Server-Timing": serverTiming,
                "Cache-Control": "private, no-store, max-age=0, must-revalidate",
            });
        } catch (err) {
            logError("[GET /api/trips] DB error", err);
            return internalErrorResponse();
        }
    });
}

