}

// 鈹€鈹€鈹€ LLM decision 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

const DECISION_PROMPT = `You are an AI operations engineer responsible for a travel SaaS platform's reliability.
You will receive detected system anomalies and current metrics.
Your job is to suggest the minimum necessary SAFE actions to remediate the issues.

STRICT SAFETY RULES 鈥?you MUST follow these:
- NEVER suggest deleting user data, disabling accounts, or stopping services
- NEVER suggest actions that could cause data loss
- Only suggest config changes, optimizations, and health checks
- Be conservative 鈥?suggest the gentlest effective action
- Only include actions you are genuinely confident about (confidence 鈮?0.7)

Available actions (use ONLY these exact type strings):
  CLEAR_CACHE               鈫?clears Redis image cache; safe at any time
  CHECK_SYSTEM              鈫?read-only health snapshot; always safe
  CHECK_AI_PROVIDER         鈫?ping AI providers; use when provider errors detected
  REDUCE_TOKENS_25PCT       鈫?reduce LLM token budget 25%; use for mild cost/latency issues
  REDUCE_TOKENS_50PCT       鈫?reduce LLM token budget 50%; use ONLY for severe cost issues
  PREFER_GEMINI             鈫?route to Gemini instead of OpenAI; use when OpenAI errors detected
  ENABLE_TIMEOUT_REDUCTION  鈫?reduce request timeouts 30%; use to fail fast under degraded conditions

Respond with valid JSON only 鈥?no markdown, no explanation outside JSON:
{
  "assessment": "OK|LOW|MEDIUM|HIGH|CRITICAL",
  "reasoning": "<1-3 sentences with actual metric values>",
  "actions": [
    { "type": "<exact type>", "reason": "<why this specific action>", "confidence": <0.0-1.0> }
  ],
  "duration_minutes": <5-120>
}

If no action is needed, return assessment "OK" with an empty actions array.`;

async function getLLMDecision(
    anomalies: Anomaly[],
    metrics:   SystemMetrics,
): Promise<LLMDecision | null> {
    const apiKey = process.env.OPENAI_API_KEY;
    if (!apiKey) return null;

    const anomalySummary = anomalies
        .map((a) => `[${a.severity.toUpperCase()}] ${a.label}: ${a.detail}`)
        .join("\n");

    const metricSummary = [
        `1h: ${metrics.h1.calls} calls, ${Math.round(metrics.h1.avgLatencyMs)}ms avg latency, error rate ${metrics.h1.total > 0 ? ((metrics.h1.errors / metrics.h1.total) * 100).toFixed(1) : 0}%`,
        `7d daily cost avg: $${metrics.d7DailyAvgCost.toFixed(5)} | 30d daily avg: $${metrics.d30DailyAvgCost.toFixed(5)}`,
    ].join("\n");

    const userContent = `Anomalies:\n${anomalySummary}\n\nMetrics:\n${metricSummary}\n\nPropose the optimal interventions.`;

    try {
        const client = new OpenAIClient(apiKey, "gpt-4.1-mini");
        const result = await client.completeChat({
            messages: [
                { role: "system", content: DECISION_PROMPT },
                { role: "user",   content: userContent },
            ],
            model:       "gpt-4.1-mini",
            temperature: 0.1,
            maxTokens:   350,
            json:        true,
            timeoutMs:   15_000,
        });

        const parsed = LLMDecisionSchema.parse(JSON.parse(result.content));

        logStructured({
            layer: "llm",
            step:  "llm-response",
            agent: "autonomous-runner",
            data:  { assessment: parsed.assessment, actions: parsed.actions.map((a) => `${a.type}:${a.confidence.toFixed(2)}`) },
        });

        return parsed;
    } catch (err) {
        logError("[AutonomousRunner] LLM decision failed", { error: (err as Error).message });
        return null;
    }
}

// 鈹€鈹€鈹€ Rule-based fallback decision 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

function ruleFallbackDecision(anomalies: Anomaly[]): LLMDecision {
    if (anomalies.length === 0) {
        return { assessment: "OK", reasoning: "No anomalies detected.", actions: [], duration_minutes: 0 };
    }

    const proposals: z.infer<typeof ActionProposalSchema>[] = [];
    const hasCost    = anomalies.some((a) => a.category === "cost");
    const hasLatency = anomalies.some((a) => a.category === "latency");
    const hasErrors  = anomalies.some((a) => a.category === "error_rate");
    const hasCrit    = anomalies.some((a) => a.severity === "critical");

    if (hasCost && hasCrit) {
        proposals.push({ type: "REDUCE_TOKENS_50PCT", reason: "Critical cost surge 鈥?aggressive token reduction", confidence: 0.80 });
    } else if (hasCost || hasLatency) {
        proposals.push({ type: "REDUCE_TOKENS_25PCT", reason: "Cost/latency issue 鈥?mild token reduction", confidence: 0.75 });
    }
    if (hasErrors) {
        proposals.push({ type: "PREFER_GEMINI",    reason: "Error rate elevated 鈥?switch to Gemini fallback", confidence: 0.75 });
        proposals.push({ type: "CHECK_AI_PROVIDER", reason: "Check provider status when errors detected",       confidence: 0.90 });
    }
    if (hasLatency) {
        proposals.push({ type: "ENABLE_TIMEOUT_REDUCTION", reason: "Latency spike 鈥?fail fast with tighter timeouts", confidence: 0.75 });
    }

    const assessment = hasCrit ? "CRITICAL" as const
        : anomalies.some((a) => a.severity === "high") ? "HIGH" as const
        : "MEDIUM" as const;

    return {
        assessment,
        reasoning:        `Rule-based fallback: ${anomalies.map((a) => a.label).join(", ")}.`,
        actions:          proposals,
        duration_minutes: hasCrit ? 90 : 30,
    };
}

// 鈹€鈹€鈹€ Action dispatch 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

/**
 * Maps AutonomousActionType 鈫?concrete executor call.
 * Returns { success, message } 鈥?never throws.
 */
async function dispatchAction(
    type:     AutonomousActionType,
    duration: number,
): Promise<{ success: boolean; message: string }> {
    try {
        switch (type) {
            case "CLEAR_CACHE": {
                const r = await executeAdminAction({ type: "CLEAR_CACHE" }, "autonomous-runner");
                return { success: r.success, message: r.message ?? (r.success ? "Done" : "Failed") };
            }
            case "CHECK_SYSTEM": {
                const r = await executeAdminAction({ type: "VERIFY_MONITORING" }, "autonomous-runner");
                return { success: r.success, message: r.message ?? (r.success ? "Done" : "Failed") };
            }
            case "CHECK_AI_PROVIDER": {
                const r = await executeAdminAction({ type: "CHECK_AI_PROVIDER" }, "autonomous-runner");
                return { success: r.success, message: r.message ?? (r.success ? "Done" : "Failed") };
            }

            case "REDUCE_TOKENS_25PCT":
                setHealingOverrides(
                    ["reduce_tokens_25pct"],
                    "MEDIUM",
                    ["autonomous-runner"],
                    "Autonomous mode: 25% token reduction applied.",
                    duration,
                );
                return { success: true, message: "Token budget reduced 25% for " + duration + " min" };

            case "REDUCE_TOKENS_50PCT":
                setHealingOverrides(
                    ["reduce_tokens_50pct"],
                    "HIGH",
                    ["autonomous-runner"],
                    "Autonomous mode: 50% token reduction applied.",
                    duration,
                );
                return { success: true, message: "Token budget reduced 50% for " + duration + " min" };

            case "PREFER_GEMINI":
                setHealingOverrides(
                    ["prefer_gemini"],
                    "HIGH",
                    ["autonomous-runner"],
                    "Autonomous mode: routing to Gemini.",
                    duration,
                );
                return { success: true, message: "Provider switched to Gemini for " + duration + " min" };

            case "ENABLE_TIMEOUT_REDUCTION":
                setHealingOverrides(
                    ["enable_timeout_reduction"],
                    "MEDIUM",
                    ["autonomous-runner"],
                    "Autonomous mode: timeout reduction applied.",
                    duration,
                );
                return { success: true, message: "Request timeouts reduced 30% for " + duration + " min" };

            default:
                return { success: false, message: `Unknown action type: ${type as string}` };
        }
    } catch (err) {
        return { success: false, message: (err as Error).message ?? "Dispatch error" };
    }
}

// 鈹€鈹€鈹€ Verification 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

/**
 * After executing actions, snapshot current metrics and check if the anomaly
 * metric has improved. No corrective action taken here 鈥?purely observational.
 */
async function verifyResolution(
    anomaly:       Anomaly,
    beforeMetrics: SystemMetrics,
): Promise<VerificationResult> {
    // Re-fetch current 1-hour metrics for a quick sanity check.
    // We don't call analyzeSystem() fully (expensive) 鈥?just check the specific metric.
    const { prisma } = await import("@/lib/prisma");
    const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);

    try {
        if (anomaly.category === "cost") {
            // Cost changes are only visible over days; acknowledge overlay applied.
            return {
                anomalyId: anomaly.id,
                label:     anomaly.label,
                resolvedImmediately: false,
                note: "Cost remediations (token reduction) take effect on future calls. Monitor over next 24h.",
            };
        }

        if (anomaly.category === "latency") {
            const h1 = await prisma.aiUsageLog.aggregate({
                where: { createdAt: { gte: oneHourAgo } }, _avg: { latencyMs: true },
            });
            const currentAvg = h1._avg.latencyMs ?? 0;
            const improved   = currentAvg > 0 && currentAvg < anomaly.metric.observed;
            return {
                anomalyId: anomaly.id,
                label:     anomaly.label,
                resolvedImmediately: improved,
                note: improved
                    ? `Latency improved: now ${Math.round(currentAvg)}ms (was ${Math.round(anomaly.metric.observed)}ms)`
                    : `Latency still elevated at ${Math.round(currentAvg)}ms. Timeout reduction applied 鈥?monitor next cycle.`,
            };
        }

        if (anomaly.category === "error_rate") {
            const [errors, total] = await Promise.all([
                prisma.aiUsageLog.count({ where: whereAiCallFailedSince(oneHourAgo) }),
                prisma.aiUsageLog.count({ where: { createdAt: { gte: oneHourAgo } } }),
            ]);
            const currentRate = total > 0 ? (errors / total) * 100 : 0;
            const improved    = currentRate < anomaly.metric.observed;
            return {
                anomalyId: anomaly.id,
                label:     anomaly.label,
                resolvedImmediately: improved,
                note: improved
                    ? `Error rate dropped: ${currentRate.toFixed(1)}% (was ${anomaly.metric.observed.toFixed(1)}%)`
                    : `Error rate unchanged at ${currentRate.toFixed(1)}%. Provider switch applied 鈥?routing to Gemini.`,
            };
        }

        if (anomaly.category === "availability") {
            const recent = await prisma.aiUsageLog.count({ where: { createdAt: { gte: oneHourAgo } } });
            return {
                anomalyId: anomaly.id,
                label:     anomaly.label,
                resolvedImmediately: recent > 0,
                note: recent > 0
                    ? `Activity restored: ${recent} calls observed since check.`
                    : "Still no activity. Provider check dispatched 鈥?review results in admin panel.",
            };
        }

        return {
            anomalyId: anomaly.id,
            label:     anomaly.label,
            resolvedImmediately: false,
            note:      "Verification deferred 鈥?no direct metric for this anomaly category.",
        };
    } catch (err) {
        return {
            anomalyId: anomaly.id,
            label:     anomaly.label,
            resolvedImmediately: false,
            note:      `Verification query failed: ${(err as Error).message}`,
        };
    }

    // Suppress unused variable warning for beforeMetrics (used in callers for logging)
    void beforeMetrics;
}

// 鈹€鈹€鈹€ Audit logging 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

async function persistCycleLog(result: AutonomousRunResult): Promise<void> {
    try {
        const { prisma } = await import("@/lib/prisma");
        await prisma.adminActionLog.create({
            data: {
                actionType: "AUTONOMOUS_CYCLE",
                payload: JSON.parse(JSON.stringify({
                    mode:              result.mode,
                    anomalyCount:      result.anomaliesDetected.length,
                    actionsProposed:   result.actionsProposed.length,
                    actionsExecuted:   result.actionsExecuted.length,
                    anomalyIds:        result.anomaliesDetected.map((a) => a.id),
                    skippedReason:     result.skippedReason,
                })) as object,
                result: JSON.parse(JSON.stringify({
                    actionsExecuted:   result.actionsExecuted,
                    verification:      result.verification,
                    durationMs:        result.durationMs,
                })) as object,
                success: result.actionsExecuted.every((a) => a.success),
                userId:  "autonomous-runner",
            },
        });
    } catch (err) {
        logError("[AutonomousRunner] Cycle log write failed", { error: (err as Error).message });
    }
}

// 鈹€鈹€鈹€ Main cycle 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

async function runCycle(): Promise<AutonomousRunResult> {
    const ranAt   = new Date().toISOString();
    const startMs = Date.now();

    const mode = getAutonomyMode();

    const skip = (reason: string): AutonomousRunResult => ({
        ranAt, mode, durationMs: Date.now() - startMs,
        skippedReason:     reason,
        anomaliesDetected: [],
        actionsProposed:   [],
        guardsApplied:     [],
        actionsExecuted:   [],
        verification:      [],
        activeCooldowns:   activeCooldowns(),
    });

    // 鈹€鈹€ 1. Mode gate 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    if (mode === "OFF") {
        return skip("Autonomous mode is OFF. Set AUTONOMY_MODE=SAFE or FULL to enable.");
    }

    // 鈹€鈹€ 2. Lock (no concurrent runs) 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    if (_isRunning) {
        return skip("Another autonomous cycle is already in progress.");
    }

    _isRunning = true;

    try {
        logStructured({ layer: "orchestrator", agent: "autonomous-runner", step: "start", data: { mode, ranAt } });

        // 鈹€鈹€ 3. Detect anomalies 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        const { anomalies, metrics } = await analyzeSystem();

        logInfo("[AutonomousRunner] detection complete", {
            anomalyCount: anomalies.length,
            ids: anomalies.map((a) => a.id),
        });

        if (anomalies.length === 0) {
            logInfo("[AutonomousRunner] no anomalies 鈥?cycle complete");
            const res = skip("No anomalies detected 鈥?system is within normal bounds.");
            res.skippedReason = res.skippedReason;
            res.anomaliesDetected = [];
            persistCycleLog(res).catch(() => {});
            return res;
        }

        // 鈹€鈹€ 4. Decide 鈥?LLM with rule-based fallback 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        const llmDecision = await getLLMDecision(anomalies, metrics);
        const decision    = llmDecision ?? ruleFallbackDecision(anomalies);

        // Convert LLM proposals to ProposedAction format (tag with primary anomaly)
        const actionsProposed: ProposedAction[] = decision.actions.map((a) => ({
            type:       a.type,
            reason:     a.reason,
            confidence: a.confidence,
            // Associate each action with the highest-severity anomaly it addresses
            anomalyId:  anomalies.find((an) =>
                (a.type.includes("TOKENS") && an.category === "cost") ||
                (a.type === "PREFER_GEMINI" && an.category === "error_rate") ||
                (a.type === "ENABLE_TIMEOUT_REDUCTION" && an.category === "latency") ||
                (a.type === "CHECK_AI_PROVIDER" && an.category === "error_rate") ||
                (a.type === "CLEAR_CACHE")
            )?.id ?? anomalies[0].id,
        }));

        // 鈹€鈹€ 5. Guard 鈥?validate each proposal 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        const guardsApplied: GuardDecision[] = actionsProposed.map((p) =>
            validateAction(p, mode)
        );

        const allowedActions = guardsApplied
            .filter((g) => g.allowed)
            .slice(0, MAX_ACTIONS_PER_RUN);

        logInfo("[AutonomousRunner] guard results", {
            proposed: actionsProposed.length,
            allowed:  allowedActions.length,
            rejected: guardsApplied.filter((g) => !g.allowed).map((g) => g.reason),
        });

        // 鈹€鈹€ 6. Execute 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        const actionsExecuted: ExecutedAction[] = [];

        for (const guard of allowedActions) {
            const dispatchResult = await dispatchAction(guard.action.type, decision.duration_minutes);

            actionsExecuted.push({
                type:      guard.action.type,
                reason:    guard.action.reason,
                success:   dispatchResult.success,
                message:   dispatchResult.message ?? "",
                anomalyId: guard.action.anomalyId,
            });

            if (dispatchResult.success) {
                markActed(guard.action.anomalyId, guard.action.type);
            }
        }

        logInfo("[AutonomousRunner] execution complete", {
            executed:  actionsExecuted.length,
            successes: actionsExecuted.filter((a) => a.success).length,
        });

        // 鈹€鈹€ 7. Verify 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        const verification: VerificationResult[] = await Promise.all(
            anomalies.map((anomaly) => verifyResolution(anomaly, metrics))
        );

        // 鈹€鈹€ 8. Compose result + log 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
        const result: AutonomousRunResult = {
            ranAt,
            mode,
            durationMs:        Date.now() - startMs,
            anomaliesDetected: anomalies,
            actionsProposed,
            guardsApplied,
            actionsExecuted,
            verification,
            activeCooldowns:   activeCooldowns(),
        };

        logStructured({
            layer: "orchestrator",
            agent: "autonomous-runner",
            step:  "end",
            data:  {
                durationMs:     result.durationMs,
                anomalies:      anomalies.length,
                executed:       actionsExecuted.length,
                mode,
            },
        });

        // Explainability log (fire-and-forget)
        logDecision({
            decisionType: "AUTONOMOUS_ACTION",
            source:       "autonomous_runner",
            reasoning:    decision.reasoning,
            inputSummary: `Mode: ${mode}. Anomalies: ${anomalies.map((a) => `${a.id}(${a.severity})`).join(", ") || "none"}. Actions proposed: ${actionsProposed.length}, allowed by guard: ${allowedActions.length}.`,
            confidence:   ASSESSMENT_CONFIDENCE[decision.assessment] ?? 0.5,
            outcome:      actionsExecuted.length > 0
                ? `Executed: ${actionsExecuted.map((a) => a.type).join(", ")}`
                : "No actions executed",
            triggeredBy: "autonomous",
        }).catch(() => {});

        persistCycleLog(result).catch(() => {});
        return result;

    } finally {
        _isRunning = false;
        _lastRunAt = new Date().toISOString();
    }
}

// 鈹€鈹€鈹€ Public entry point 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

/**
 * Run one full autonomous cycle.
 *
 * Wrapped in a 60-second hard timeout so a hung DB query or LLM call
 * cannot block the server indefinitely.
 */
export async function runAutonomousCycle(): Promise<AutonomousRunResult> {
    const timeout = new Promise<never>((_, reject) =>
        setTimeout(() => reject(new Error("Autonomous cycle timed out after 60s")), RUN_TIMEOUT_MS)
    );

    try {
        return await Promise.race([runCycle(), timeout]);
    } catch (err) {
        _isRunning = false; // Ensure lock is always released
        const reason = (err as Error).message ?? "Unknown error";
        logError("[AutonomousRunner] Cycle error", { error: reason });

        return {
            ranAt:             new Date().toISOString(),
            mode:              getAutonomyMode(),
            durationMs:        RUN_TIMEOUT_MS,
            skippedReason:     `Cycle failed: ${reason}`,
            anomaliesDetected: [],
            actionsProposed:   [],
            guardsApplied:     [],
            actionsExecuted:   [],
            verification:      [],
            activeCooldowns:   activeCooldowns(),
        };
    } finally {
        _lastRunAt = new Date().toISOString();
    }
}

/**
 * src/services/ai/healingStore.ts
 *
 * In-process singleton that holds the current auto-healing overrides.
 *
 * Why in-memory (not DB):
 *  - Healing actions need zero-latency application on every LLM call
 *  - The modelRouter.ts must stay synchronous 鈥?no await allowed there
 *  - Cold-start resets are acceptable; the engine re-evaluates in the next
 *    run cycle and can restore state from DB audit logs if needed
 *
 * Thread safety: Node.js is single-threaded; no mutex needed.
 *
 * External usage:
 *  - autoHealing.service.ts  鈥?writes new healing overrides
 *  - modelRouter.ts           鈥?reads overrides via applyHealingOverrides()
 *  - /api/admin/auto-heal     鈥?reads status for admin visibility
 */

import { logInfo, logError } from "@/infrastructure/logger";

// 鈹€鈹€鈹€ Types 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

/** Actions the LLM decision layer can prescribe. */
export type HealingAction =
    | "reduce_tokens_25pct"
    | "reduce_tokens_50pct"
    | "prefer_gemini"
    | "enable_timeout_reduction"
    | "clear_healing"
    | "no_action";

export interface HealingOverrides {
    /** Multiply maxTokens from modelRouter by this factor (0鈥?). 1 = no change. */
    maxTokensMultiplier:    number;
    /** If true, swap "openai" 鈫?"gemini" when GEMINI_API_KEY is present. */
    preferFallbackProvider: boolean;
    /** If true, reduce all timeoutMs values by 30 %. */
    reduceTimeouts:         boolean;
    /** Human-readable list of currently active remediations. */
    activeActions:          HealingAction[];
    /** ISO timestamp when the overrides were applied. */
    appliedAt:              string | null;
    /** ISO timestamp when overrides auto-expire. null = never (until cleared). */
    expiresAt:              string | null;
    /** Trigger: anomaly label(s) that caused this healing cycle. */
    triggers:               string[];
    /** LLM-generated reasoning for the current overrides. */
    reasoning:              string;
}

export type HealingAssessment = "OK" | "LOW" | "MEDIUM" | "HIGH" | "CRITICAL";

/** Full status snapshot returned to the admin API. */
export interface HealingStatus {
    active:       boolean;
    assessment:   HealingAssessment;
    overrides:    HealingOverrides;
    lastRunAt:    string | null;
    nextRunAt:    string | null;
    runCount:     number;
}

// 鈹€鈹€鈹€ Default / cleared state 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

const NEUTRAL_OVERRIDES: HealingOverrides = {
    maxTokensMultiplier:    1.0,
    preferFallbackProvider: false,
    reduceTimeouts:         false,
    activeActions:          [],
    appliedAt:              null,
    expiresAt:              null,
    triggers:               [],
    reasoning:              "System is within normal operating parameters.",
};

// 鈹€鈹€鈹€ Singleton state 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

let _overrides: HealingOverrides = { ...NEUTRAL_OVERRIDES };
let _assessment: HealingAssessment = "OK";
let _lastRunAt: string | null = null;
let _nextRunAt: string | null = null;
let _runCount = 0;

// 鈹€鈹€鈹€ Public API 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

export function getHealingStatus(): HealingStatus {
    // Auto-expire: if expiresAt is in the past, clear overrides before returning
    if (_overrides.expiresAt && new Date(_overrides.expiresAt) < new Date()) {
        logInfo("[HealingStore] overrides expired 鈥?auto-clearing");
        clearHealingOverrides("auto-expiry");
    }

    return {
        active:    _overrides.activeActions.length > 0,
        assessment: _assessment,
        overrides: { ..._overrides },
        lastRunAt: _lastRunAt,
        nextRunAt: _nextRunAt,
        runCount:  _runCount,
    };
}

export function setHealingOverrides(
    actions:         HealingAction[],
    assessment:      HealingAssessment,
    triggers:        string[],
    reasoning:       string,
    durationMinutes: number,
): void {
    const now = new Date();

    _overrides = {
        maxTokensMultiplier:    computeTokenMultiplier(actions),
        preferFallbackProvider: actions.includes("prefer_gemini") && !!process.env.GEMINI_API_KEY,
        reduceTimeouts:         actions.includes("enable_timeout_reduction"),
        activeActions:          actions.filter((a) => a !== "no_action" && a !== "clear_healing"),
        appliedAt:              now.toISOString(),
        expiresAt:              durationMinutes > 0
            ? new Date(now.getTime() + durationMinutes * 60 * 1000).toISOString()
            : null,
        triggers,
        reasoning,
    };

    _assessment = assessment;
    _lastRunAt  = now.toISOString();
    _runCount  += 1;

    logInfo("[HealingStore] overrides applied", {
        assessment,
        actions: _overrides.activeActions,
        maxTokensMultiplier: _overrides.maxTokensMultiplier,
        preferGemini: _overrides.preferFallbackProvider,
        expiresAt: _overrides.expiresAt,
    });
}

export function clearHealingOverrides(reason = "manual"): void {
    if (_overrides.activeActions.length === 0) return;
    logInfo("[HealingStore] overrides cleared", { reason, previous: _overrides.activeActions });
    _overrides  = { ...NEUTRAL_OVERRIDES };
    _assessment = "OK";
    _lastRunAt  = new Date().toISOString();
    _runCount  += 1;
}

export function recordRunTimestamps(lastRun: Date, intervalMinutes: number): void {
    _lastRunAt = lastRun.toISOString();
    _nextRunAt = new Date(lastRun.getTime() + intervalMinutes * 60 * 1000).toISOString();
}

// 鈹€鈹€鈹€ Model router integration 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

export interface ModelConfigShape {
    provider:    "openai" | "gemini";
    model:       string;
    maxTokens:   number;
    timeoutMs:   number;
    temperature: number;
}

/**
 * Called by modelRouter.selectModelConfig() before returning.
 * Applies any active healing overrides to the resolved config.
 */
export function applyHealingOverrides<T extends ModelConfigShape>(config: T): T {
    // Check expiry inline (synchronous hot path, no I/O)
    if (_overrides.expiresAt && new Date(_overrides.expiresAt) < new Date()) {
        clearHealingOverrides("auto-expiry");
        return config;
    }

    if (_overrides.activeActions.length === 0) return config;

    const result = { ...config };

    // Token reduction
    if (_overrides.maxTokensMultiplier < 1.0) {
        result.maxTokens = Math.max(256, Math.floor(config.maxTokens * _overrides.maxTokensMultiplier));
    }

    // Provider switch (openai 鈫?gemini)
    if (_overrides.preferFallbackProvider && config.provider === "openai") {
        result.provider = "gemini";
        // Keep same model family tier 鈥?we don't rewrite the model string here;
        // the existing fallback chain in executeWithRetry handles provider routing.
    }

    // Timeout reduction (30%)
    if (_overrides.reduceTimeouts) {
        result.timeoutMs = Math.max(10_000, Math.floor(config.timeoutMs * 0.7));
    }

    return result;
}

// 鈹€鈹€鈹€ Helpers 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

function computeTokenMultiplier(actions: HealingAction[]): number {
    if (actions.includes("reduce_tokens_50pct")) return 0.5;
    if (actions.includes("reduce_tokens_25pct")) return 0.75;
    return 1.0;
}

