    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const recognitionRef = useRef<any>(null);
    const [isListening, setIsListening] = useState(false);
    const [micSupported, setMicSupported] = useState(false);

    // 鈹€鈹€ Session identity 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    // Stable UUID for the lifetime of this page visit. Sent with every landing
    // request so the server can maintain short-term conversational memory
    // (follow-up questions reference the same session context).
    const sessionIdRef = useRef<string>("");
    useEffect(() => {
        sessionIdRef.current = crypto.randomUUID();
    }, []);

    // 鈹€鈹€ Typewriter engine refs 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    // incomingRef accumulates every character received from the server.
    // displayedLenRef tracks how many of those chars are currently on screen.
    // The RAF loop drains the gap between the two at an adaptive pace.
    const incomingRef = useRef("");
    const displayedLenRef = useRef(0);
    const streamEndedRef = useRef(false);
    const rafRef = useRef<number | null>(null);
    const inputRef = useRef<HTMLInputElement>(null);
    const pendingActionRef = useRef<string | null>(null);

    // 鈹€鈹€ Hydration guard + mic support detection 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    useEffect(() => {
        setIsClient(true);
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const SR = (window as any).SpeechRecognition ?? (window as any).webkitSpeechRecognition;
        setMicSupported(!!SR);
    }, []);

    // 鈹€鈹€ Global cleanup on unmount 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    useEffect(() => {
