    const handleCancel = useCallback(() => {
        abortRef.current?.abort();
        stopTypewriter();
        incomingRef.current = "";
        displayedLenRef.current = 0;
        streamEndedRef.current = false;
        submittingRef.current = false;
        pendingActionRef.current = null;
        setPhase("idle");
        setDisplayedText("");
        setPostAnswerActions(null);
    }, [stopTypewriter]);

    // 鈹€鈹€ Core submit 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
