                    method: "POST",
                    credentials: "include",
                    signal: controller.signal,
                    headers: {
                        "Content-Type": "application/json",
                        ...(csrfToken ? { "X-CSRF-Token": csrfToken } : {}),
                        ...(accessToken ? { Authorization: `Bearer ${accessToken}` } : {}),
                    },
                    body: JSON.stringify({
                        prompt: finalPrompt.slice(0, 500),
                        sessionId: sessionIdRef.current,
                    }),
                });

