"use client";

import { useEffect, useRef, useState, useMemo } from "react";
import { motion, AnimatePresence, useReducedMotion } from "framer-motion";
import { Sparkles, Brain, TrendingUp, AlertTriangle, ChefHat, MapPin, Hotel, DollarSign, Shield, Lightbulb } from "lucide-react";
import { AGENT_REGISTRY } from "./agentRegistry";
import type { FlowStage, FlowState } from "./types";

// 鈹€鈹€鈹€ Message types 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

interface AIMessage {
    id: string;
    type: "insight" | "observation" | "suggestion" | "thinking" | "celebration" | "fact";
    text: string;
    icon?: React.ReactNode;
    accent?: string;
    timestamp?: number;
}

// 鈹€鈹€鈹€ Generate data-driven insights from actual trip state 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

function generateInsights(state: FlowState): AIMessage[] {
    const msgs: AIMessage[] = [];
    const { stage, plannerResult, researchResult, logisticsResult, budgetResult, safetyResult, input } = state;

    // Opening 鈥?always present
    msgs.push({
        id: "welcome",
        type: "observation",
        text: `I'm building your ${input.destination} trip. Let me handle the heavy lifting 鈥?you just steer.`,
        icon: <Sparkles className="w-3.5 h-3.5" />,
        accent: "from-indigo-500 to-purple-500",
    });
    
    // Random fact to "make it work" as requested by user
    if (input.destination) {
        msgs.push({
            id: "destination-fact",
            type: "fact",
            text: `Did you know? ${input.destination} is known for its unique blend of traditional culture and modern efficiency. I'll make sure your itinerary reflects the best of both.`,
            icon: <Lightbulb className="w-3.5 h-3.5" />,
            accent: "from-cyan-500 to-blue-500",
        });
    }

    // 鈹€鈹€ Planner insights 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    if (plannerResult) {
        const days = plannerResult.durationDays;
        const themes = plannerResult.days.map((d) => d.theme);
        const uniqueThemes = new Set(themes).size;
        const style = plannerResult.preferences?.style;
        const pace = plannerResult.preferences?.pace;

        msgs.push({
            id: "plan-structure",
            type: "insight",
            text: `I've mapped out ${days} days with ${uniqueThemes} distinct themes. ${
                style === "adventure"
                    ? "Leaning into adventure 鈥?expect some adrenaline."
                    : style === "relaxed"
                    ? "Keeping it chill 鈥?quality over quantity."
                    : style === "luxury"
                    ? "Premium picks incoming 鈥?the finer things."
                    : "A balanced mix of experiences."
            }`,
            icon: <Brain className="w-3.5 h-3.5" />,
            accent: "from-indigo-500 to-indigo-400",
        });

        if (pace === "fast") {
            msgs.push({
                id: "plan-pace-warning",
                type: "suggestion",
                text: "Fast pace selected 鈥?I'll pack in activities, but consider slowing down if you want deeper experiences.",
                icon: <TrendingUp className="w-3.5 h-3.5" />,
                accent: "from-amber-500 to-orange-500",
            });
        }

        const hasDuplicateThemes = uniqueThemes < themes.length;
        if (hasDuplicateThemes) {
            msgs.push({
                id: "plan-variety",
                type: "suggestion",
                text: "Some days share the same theme. Tap a day card to mix it up for more variety.",
                icon: <Lightbulb className="w-3.5 h-3.5" />,
                accent: "from-indigo-500 to-violet-500",
            });
        }
    }

    // 鈹€鈹€ Research insights 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    if (researchResult) {
        const totalActivities = researchResult.days.reduce((s, d) => s + d.activities.length, 0);
        const hotelCount = researchResult.hotels.length;
        const types = researchResult.days.flatMap((d) => d.activities.map((a) => a.type));
        const restaurants = types.filter((t) => t === "restaurant").length;
        const experiences = types.filter((t) => t === "experience").length;
        const attractions = types.filter((t) => t === "attraction").length;

        msgs.push({
            id: "research-found",
            type: "insight",
            text: `Found ${totalActivities} activities across ${researchResult.days.length} days 鈥?${attractions} attractions, ${experiences} experiences, and ${restaurants} restaurants. ${hotelCount} hotel options ready.`,
            icon: <MapPin className="w-3.5 h-3.5" />,
            accent: "from-teal-500 to-emerald-500",
        });

        if (restaurants === 0) {
            msgs.push({
                id: "research-no-food",
                type: "suggestion",
                text: "No restaurant picks yet. Hit \"Find different activities\" and ask for more food experiences 鈥?trust me, local food is half the trip.",
                icon: <ChefHat className="w-3.5 h-3.5" />,
                accent: "from-amber-500 to-orange-500",
            });
        } else if (restaurants >= totalActivities * 0.4) {
            msgs.push({
                id: "research-food-heavy",
                type: "observation",
                text: `${Math.round((restaurants / totalActivities) * 100)}% of your activities are food-related. That's a culinary trip 鈥?perfect if intentional.`,
                icon: <ChefHat className="w-3.5 h-3.5" />,
                accent: "from-teal-500 to-cyan-500",
            });
        }

        if (hotelCount > 1) {
            msgs.push({
                id: "research-hotels",
                type: "suggestion",
                text: `I found ${hotelCount} hotel options across different price ranges. Scroll through them below 鈥?your choice affects route optimization next.`,
                icon: <Hotel className="w-3.5 h-3.5" />,
                accent: "from-teal-500 to-teal-400",
            });
        }
    }

    // 鈹€鈹€ Logistics insights 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    if (logisticsResult) {
        const hotel = logisticsResult.selectedHotel;
        const totalActs = logisticsResult.days.reduce((s, d) => s + d.activities.length, 0);
        const mornings = logisticsResult.days.flatMap((d) => d.activities.filter((a) => a.timeSlot === "morning")).length;
        const evenings = logisticsResult.days.flatMap((d) => d.activities.filter((a) => a.timeSlot === "evening")).length;

        msgs.push({
            id: "logistics-optimized",
            type: "insight",
            text: `Route optimized 鈥?${totalActs} activities sequenced by geography and time. ${
                hotel ? `Staying at ${hotel.name}.` : ""
            }`,
            icon: <MapPin className="w-3.5 h-3.5" />,
            accent: "from-amber-500 to-amber-400",
        });

        if (mornings > evenings * 2) {
            msgs.push({
                id: "logistics-morning-heavy",
                type: "observation",
                text: "Your mornings are packed 鈥?evenings are lighter. Consider adding a dinner spot or night experience.",
                icon: <TrendingUp className="w-3.5 h-3.5" />,
                accent: "from-amber-500 to-orange-500",
            });
        }
    }

    // 鈹€鈹€ Budget insights 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    if (budgetResult) {
        const total = budgetResult.budget.totalEstimatedCost;
        const userBudget = budgetResult.preferences?.budget;
        const isOver = budgetResult.budget.isOverBudget;
        const perDay = Math.round(total / budgetResult.durationDays);

        if (isOver && userBudget) {
            const gap = total - userBudget;
            msgs.push({
                id: "budget-over",
                type: "suggestion",
                text: `You're $${Math.round(gap).toLocaleString()} over budget. I have specific suggestions to bring it down 鈥?check below. Or, hit "Optimize for lower cost" and I'll reroute.`,
                icon: <AlertTriangle className="w-3.5 h-3.5" />,
                accent: "from-rose-500 to-pink-500",
            });
        } else {
            msgs.push({
                id: "budget-ok",
                type: "insight",
                text: `Total estimate: $${total.toLocaleString()} (~$${perDay}/day). ${
                    userBudget ? `That's within your $${userBudget.toLocaleString()} budget.` : "Looking reasonable."
                }`,
                icon: <DollarSign className="w-3.5 h-3.5" />,
                accent: "from-emerald-500 to-emerald-400",
            });
        }
    }

    // 鈹€鈹€ Safety insights 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    if (safetyResult) {
        const { riskLevel, warnings, tips } = safetyResult.safety;

        msgs.push({
            id: "safety-verdict",
            type: riskLevel === "high" ? "suggestion" : "insight",
            text: riskLevel === "low"
                ? `Looking good 鈥?${input.destination} is rated low risk. ${tips.length} travel tips ready for you.`
                : riskLevel === "medium"
                ? `${warnings.length} things to watch for in ${input.destination}. I've flagged them below 鈥?nothing dealbreaking.`
                : `Heads up 鈥?${input.destination} has some higher-risk factors. Review the ${warnings.length} warnings carefully.`,
            icon: <Shield className="w-3.5 h-3.5" />,
            accent: riskLevel === "low" ? "from-emerald-500 to-teal-500" : riskLevel === "medium" ? "from-amber-500 to-orange-500" : "from-rose-500 to-red-500",
        });

        msgs.push({
            id: "safety-final",
            type: "celebration",
            text: "Your trip is ready. Every detail has been planned, researched, routed, budgeted, and safety-checked. Hit save when you're happy.",
            icon: <Sparkles className="w-3.5 h-3.5" />,
            accent: "from-indigo-500 to-purple-500",
        });
    }

    return msgs;
}

// 鈹€鈹€鈹€ Typewriter text component 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

function TypewriterText({ text, speed = 18 }: { text: string; speed?: number }) {
    const [displayed, setDisplayed] = useState("");
    const prefersReduced = useReducedMotion();

    useEffect(() => {
        if (prefersReduced) {
            setDisplayed(text);
            return;
        }
        setDisplayed("");
        let i = 0;
        const interval = setInterval(() => {
            i++;
            setDisplayed(text.slice(0, i));
            if (i >= text.length) clearInterval(interval);
        }, speed);
        return () => clearInterval(interval);
    }, [text, speed, prefersReduced]);

    return (
        <span>
            {displayed}
            {displayed.length < text.length && (
                <motion.span
                    className="inline-block w-[2px] h-[14px] bg-indigo-400 ml-0.5 align-middle rounded-full"
                    animate={{ opacity: [1, 0, 1] }}
                    transition={{ duration: 0.6, repeat: Infinity }}
                />
            )}
        </span>
    );
}

// 鈹€鈹€鈹€ Thinking dots 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

function ThinkingDots() {
    return (
        <div className="flex items-center gap-3 px-4 py-3">
            <div className="w-7 h-7 rounded-full bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center flex-shrink-0">
                <Sparkles className="w-3 h-3 text-white" />
            </div>
            <div className="flex items-center gap-1.5 bg-white/[0.04] rounded-2xl px-4 py-2.5 border border-white/[0.06]">
                {[0, 1, 2].map((i) => (
                    <motion.span
                        key={i}
                        className="w-1.5 h-1.5 rounded-full bg-indigo-400"
                        animate={{ opacity: [0.3, 1, 0.3], scale: [0.8, 1.1, 0.8] }}
