                                ? `${agent.name} is analyzing...`
                                : `${visibleMessages.length} insights`
                            }
                        </span>
                    </div>
                    <span className="text-[10px] text-slate-600">
                        <kbd className="bg-white/[0.06] border border-white/[0.08] rounded px-1 py-0.5 font-mono text-[9px] text-slate-500">?</kbd>
                        {" "}details
                    </span>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { motion, useReducedMotion, AnimatePresence } from "framer-motion";
import { Check } from "lucide-react";
import { AGENT_REGISTRY } from "./agentRegistry";
import type { FlowStage, FlowMetadata } from "./types";

const STAGES: Exclude<FlowStage, "saved">[] = [
    "planner",
    "research",
    "logistics",
    "budget",
    "safety",
];

const STAGE_LABELS: Record<Exclude<FlowStage, "saved">, string> = {
