"use client";

import { useEffect, useState } from "react";
import { motion, useReducedMotion, AnimatePresence } from "framer-motion";
import { RefreshCw } from "lucide-react";
import { AGENT_REGISTRY, agentColorClasses } from "./agentRegistry";
import type { FlowStage } from "./types";

interface AgentThinkingCardProps {
    stage: Exclude<FlowStage, "saved">;
    isError?: boolean;
    errorMessage?: string;
    onRetry?: () => void;
    skeleton?: React.ReactNode;
    /**
     * Destination name interpolated into any `{destination}` tokens inside
     * the agent's rotating loading messages. Falls back to "your trip" when
     * not provided so taglines remain grammatical.
     */
    destination?: string;
}

/** Replaces {destination} token with the actual destination name. */
function interpolateMessage(msg: string, destination: string | undefined): string {
    const fallback = destination?.trim() || "your trip";
    return msg.replace(/\{destination\}/g, fallback);
}

/** How long each rotating tagline stays on screen before fading to the next. */
const MESSAGE_ROTATION_MS = 2800;

export function AgentThinkingCard({
    stage,
    isError = false,
    errorMessage,
    onRetry,
    skeleton,
    destination,
}: AgentThinkingCardProps) {
    const agent = AGENT_REGISTRY[stage];
    const colors = agentColorClasses(agent.color);
    const prefersReduced = useReducedMotion();

    const [visibleLogs, setVisibleLogs] = useState<string[]>([]);
    const [logIndex, setLogIndex] = useState(0);
    const [messageIndex, setMessageIndex] = useState(0);

    useEffect(() => {
        if (isError) return;
        setVisibleLogs([]);
        setLogIndex(0);
        setMessageIndex(0);
    }, [stage, isError]);

    useEffect(() => {
        if (isError || logIndex >= agent.logs.length) return;
        const timer = setTimeout(() => {
            setVisibleLogs((prev) => [...prev, agent.logs[logIndex]]);
            setLogIndex((i) => i + 1);
        }, prefersReduced ? 0 : 1200);
        return () => clearTimeout(timer);
    }, [logIndex, agent.logs, isError, prefersReduced]);

    // Rotate through the agent's tagline messages while loading. Skipped entirely
    // under reduced-motion so the first message stays pinned.
    useEffect(() => {
        if (isError || prefersReduced || agent.messages.length <= 1) return;
        const interval = setInterval(() => {
            setMessageIndex((i) => (i + 1) % agent.messages.length);
        }, MESSAGE_ROTATION_MS);
        return () => clearInterval(interval);
    }, [agent.messages, isError, prefersReduced]);

    const Icon = agent.icon;
    const currentMessage = interpolateMessage(
        agent.messages[messageIndex] ?? agent.messages[0] ?? "",
        destination,
    );

    return (
        <div className="w-full space-y-6">
            {/* Agent card */}
            <div className="card-premium ai-shimmer p-6">
                <div className="flex items-start gap-4 relative">
                    {/* Avatar with breathing glow */}
                    <div className="relative flex-shrink-0">
                        <motion.div
                            className={`w-14 h-14 rounded-2xl flex items-center justify-center border-2 ${
                                isError
                                    ? "border-rose-500/50 bg-rose-500/10"
                                    : `${colors.border} ${colors.bg}`
                            }`}
                            animate={
                                prefersReduced || isError
                                    ? {}
                                    : {
                                          boxShadow: [
                                              `0 0 0px ${agent.glow}`,
                                              `0 0 28px ${agent.glow}`,
                                              `0 0 0px ${agent.glow}`,
                                          ],
                                      }
                            }
                            transition={{ duration: 2.4, repeat: Infinity, ease: "easeInOut" }}
                        >
                            <Icon
                                className={`w-6 h-6 ${isError ? "text-rose-400" : colors.text}`}
                            />
                        </motion.div>

                        {!isError && !prefersReduced && (
                            <motion.div
                                className={`absolute inset-0 rounded-2xl border-2 ${colors.border} opacity-30`}
                                animate={{ rotate: 360 }}
                                transition={{ duration: 3, repeat: Infinity, ease: "linear" }}
                            />
                        )}

                        {/* Pulse dot */}
                        {!isError && (
                            <motion.div
                                className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full ${colors.fill} border-2 border-[#0B0F19]`}
                                animate={prefersReduced ? {} : { scale: [1, 1.3, 1], opacity: [1, 0.6, 1] }}
                                transition={{ duration: 1.5, repeat: Infinity }}
                            />
                        )}
                    </div>

                    <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-1.5">
                            <span className="text-sm font-bold text-white">
                                {agent.name}
                            </span>
                            <span className="text-[10px] text-slate-500 border border-white/[0.06] rounded-full px-2 py-0.5">
                                AI Agent
                            </span>
                        </div>

                        {isError ? (
                            <p className="text-sm leading-relaxed text-rose-400">
                                Agent encountered an issue
                            </p>
                        ) : prefersReduced ? (
                            <p className="text-sm leading-relaxed text-slate-400">
                                {currentMessage}
                            </p>
                        ) : (
                            <div className="relative min-h-[1.5rem]">
                                <AnimatePresence mode="wait">
                                    <motion.p
                                        key={messageIndex}
                                        initial={{ opacity: 0, y: 4 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        exit={{ opacity: 0, y: -4 }}
                                        transition={{ duration: 0.32, ease: [0.22, 1, 0.36, 1] }}
                                        className="text-sm leading-relaxed text-slate-400"
                                    >
                                        {currentMessage}
                                    </motion.p>
                                </AnimatePresence>
                            </div>
                        )}

                        {isError && errorMessage && (
                            <p className="mt-2 text-xs text-rose-400/70 font-mono break-words bg-rose-500/5 rounded-lg px-3 py-2">
                                {errorMessage}
                            </p>
                        )}

                        {/* Typewriter log lines */}
                        {!isError && (
                            <div className="mt-4 space-y-2 font-mono">
                                {visibleLogs.map((line, i) => (
                                    <motion.div
                                        key={i}
                                        initial={prefersReduced ? {} : { opacity: 0, x: -8 }}
                                        animate={{ opacity: 1, x: 0 }}
                                        transition={{ duration: 0.3 }}
                                        className="flex items-center gap-2.5 text-[11px] text-slate-500"
                                    >
                                        <motion.span
                                            className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${colors.fill}`}
                                            animate={i === visibleLogs.length - 1 && !prefersReduced ? { opacity: [1, 0.3, 1] } : {}}
                                            transition={{ duration: 0.8, repeat: Infinity }}
                                        />
                                        {line}
                                    </motion.div>
                                ))}
                                {/* Blinking cursor */}
                                {logIndex < agent.logs.length && (
                                    <motion.span
                                        className={`inline-block w-1.5 h-4 ${colors.fill} rounded-sm`}
                                        animate={prefersReduced ? {} : { opacity: [1, 0, 1] }}
                                        transition={{ duration: 0.8, repeat: Infinity }}
                                    />
                                )}
                            </div>
                        )}

                        {isError && (
                            <button
                                onClick={onRetry}
                                className="mt-3 flex items-center gap-2 text-sm text-rose-400 hover:text-rose-300 transition-all duration-200 hover:translate-x-0.5"
                            >
                                <RefreshCw className="w-3.5 h-3.5" />
                                Try again
                            </button>
                        )}
                    </div>
                </div>
            </div>

            {/* Skeleton */}
            {skeleton && !isError && (
                <div className="opacity-50 pointer-events-none select-none relative">
                    <div className="absolute inset-0 bg-gradient-to-b from-transparent to-[#0B0F19] z-10" />
                    {skeleton}
                </div>
            )}

            {!skeleton && !isError && <DefaultSkeleton colors={colors} />}
        </div>
    );
}

function DefaultSkeleton({ colors }: { colors: ReturnType<typeof agentColorClasses> }) {
    return (
        <div className="space-y-4 opacity-50 pointer-events-none select-none relative">
            <div className="absolute inset-0 bg-gradient-to-b from-transparent to-[#0B0F19] z-10" />
            <div className="h-48 bg-white/[0.03] rounded-2xl ai-shimmer border border-white/[0.05]" />
            {[1, 2, 3].map((i) => (
                <div
                    key={i}
                    className="bg-white/[0.02] border border-white/[0.05] rounded-2xl p-4 space-y-3 ai-shimmer"
                    style={{ animationDelay: `${i * 0.3}s` }}
                >
                    <div className="flex items-center gap-3">
                        <div className={`w-8 h-8 rounded-xl ${colors.bg}`} />
                        <div className="flex-1 space-y-2">
                            <div className="h-3 bg-white/[0.06] rounded-full w-1/3" />
                            <div className="h-2 bg-white/[0.04] rounded-full w-2/3" />
                        </div>
                    </div>
                    <div className="grid grid-cols-3 gap-2">
                        {[1, 2, 3].map((j) => (
                            <div key={j} className="h-16 bg-white/[0.03] rounded-xl border border-white/[0.05]" />
                        ))}
                    </div>
                </div>
            ))}
        </div>
    );
}

"use client";

/**
 * ItineraryCreationFlow 鈥?Master orchestrator for the 5-stage agent pipeline.
 *
 * Renders as a full-screen fixed overlay (z-50 inset-0 bg-[#0A0D12]).
 * Coordinates all stage components, state machine, explainability panel,
 * save celebration, and session resume.
 */

import { useCallback, useEffect, useRef, useState } from "react";
import { createPortal } from "react-dom";
import { useRouter } from "next/navigation";
import { motion, AnimatePresence, useReducedMotion } from "framer-motion";
import { WifiOff } from "lucide-react";
import confetti from "canvas-confetti";

import { useFlowState } from "./useFlowState";
import { AgentPipelineHeader } from "./AgentPipelineHeader";
import { TripDNASummaryStrip } from "./TripDNASummaryStrip";
import { ExplainabilityPanel } from "./ExplainabilityPanel";
import { AISuggestionsPanel } from "./AISuggestionsPanel";
import { SystemHeader } from "./SystemHeader";
import { ReasoningPanel } from "./ReasoningPanel";
import { PlannerStage } from "./stages/PlannerStage";
import { ResearchStage } from "./stages/ResearchStage";
import { LogisticsStage } from "./stages/LogisticsStage";
import { BudgetStage } from "./stages/BudgetStage";
import { SafetyStage } from "./stages/SafetyStage";
import type { FlowInput, FlowStage, TripContext, EnrichedTripContext, OptimizedTripContext } from "./types";
import { ensureCsrfToken } from "@/lib/api";

interface ItineraryCreationFlowProps {
    tripId: string;
    input: FlowInput;
    onComplete: (tripId: string) => void;
    onClose: () => void;
}

// 鈹€鈹€鈹€ Stage transition variants 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

const stageVariants = {
    initial: { opacity: 0, y: 24 },
    animate: { opacity: 1, y: 0 },
    exit: { opacity: 0, y: -16 },
};

const stageTransition = { type: "spring" as const, stiffness: 300, damping: 30 };

// 鈹€鈹€鈹€ Toast 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

function Toast({ message, variant = "success" }: { message: string; variant?: "success" | "error" | "info" }) {
    const bg =
        variant === "success"
            ? "bg-emerald-500/10 border-emerald-500/30 text-emerald-300"
            : variant === "error"
            ? "bg-rose-500/10 border-rose-500/30 text-rose-300"
            : "bg-white/[0.08] border-white/[0.15] text-slate-200";

    return (
        <motion.div
            initial={{ opacity: 0, y: 16, scale: 0.96 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: -8 }}
            className={`fixed bottom-24 left-1/2 -translate-x-1/2 z-[70] border rounded-2xl px-5 py-3 text-sm font-medium shadow-xl backdrop-blur-xl whitespace-nowrap ${bg}`}
        >
            {message}
        </motion.div>
    );
}

// 鈹€鈹€鈹€ Session resume banner 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

// 鈹€鈹€鈹€ Main component 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

export function ItineraryCreationFlow({ tripId, input, onComplete, onClose }: ItineraryCreationFlowProps) {
    const router = useRouter();
    const prefersReduced = useReducedMotion();
    const flowInput: FlowInput = { ...input, tripId };

    const { state, dispatch, resetAllAndRestart } = useFlowState(flowInput);

    const [isLoading, setIsLoading] = useState(false);
    const [explainOpen, setExplainOpen] = useState(false);
    const [explainStage, setExplainStage] = useState<Exclude<FlowStage, "saved">>("planner");
    const [toast, setToast] = useState<{ message: string; variant?: "success" | "error" | "info" } | null>(null);
    const [isSaving, setIsSaving] = useState(false);
    const [isOffline, setIsOffline] = useState(false);
    const [mounted, setMounted] = useState(false);
    // Becomes true once the CSRF token is confirmed in the ref 鈥?gates the auto-start.
    const [csrfReady, setCsrfReady] = useState(false);

    const csrfTokenRef = useRef<string>("");

    useEffect(() => {
        setMounted(true);
        // Fetch (or read from cookie) the CSRF token BEFORE the planner auto-starts.
        ensureCsrfToken()
            .then((t) => {
                csrfTokenRef.current = t;
            })
            .catch(() => {
                // Even on failure, unblock the planner 鈥?callApi has its own retry.
            })
            .finally(() => {
                setCsrfReady(true);
            });
    }, []);

    // Offline detection
    useEffect(() => {
        setIsOffline(!navigator.onLine);
        const on = () => setIsOffline(false);
        const off = () => setIsOffline(true);
        window.addEventListener("online", on);
        window.addEventListener("offline", off);
        return () => { window.removeEventListener("online", on); window.removeEventListener("offline", off); };
    }, []);

    // Global keyboard shortcuts
    useEffect(() => {
        function handler(e: KeyboardEvent) {
            if (e.key === "?" && !e.shiftKey) {
                e.preventDefault();
                setExplainOpen((o) => !o);
            }
            if (e.key === "Escape" && !explainOpen) {
                // Esc closes only if not in a text field
                if (document.activeElement?.tagName !== "TEXTAREA" && document.activeElement?.tagName !== "INPUT") {
                    onClose();
                }
            }
        }
        document.addEventListener("keydown", handler);
        return () => document.removeEventListener("keydown", handler);
    }, [explainOpen, onClose]);

    function showToast(message: string, variant?: "success" | "error" | "info") {
        setToast({ message, variant });
        setTimeout(() => setToast(null), 3500);
    }

    // 鈹€鈹€鈹€ API calls 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

    async function callApi<T>(endpoint: string, body: unknown): Promise<T> {
        // Use the pre-fetched cached token; fall back to a fresh fetch.
        let csrfToken = csrfTokenRef.current || (await ensureCsrfToken());
        // Stage-aware timeout:
        //   research 鈥?Bright Data + LLM + dense-city dual-query geocoding can
        //              take 60鈥?20 s for long multi-day luxury trips 鈫?150 s.
        //   all other stages 鈥?90 s covers worst-case LLM + routing latency.
        const timeoutMs = endpoint === "research" ? 150_000 : 90_000;
        const timeoutSignal = AbortSignal.timeout(timeoutMs);

        const doRequest = async (token: string) =>
            fetch(`/api/ai/itinerary-flow/${endpoint}`, {
                method: "POST",
                credentials: "include",
                headers: {
                    "Content-Type": "application/json",
                    "X-CSRF-Token": token,
                    // Thread the stable session ID through all pipeline calls for
                    // request correlation in server logs and agent replay entries.
                    "X-Flow-Session-Id": state.sessionId,
                },
                body: JSON.stringify(body),
                signal: timeoutSignal,
            });

        let res = await doRequest(csrfToken);

        // If CSRF was rejected (403), refresh the token once and retry.
        if (res.status === 403) {
            csrfToken = await ensureCsrfToken();
            csrfTokenRef.current = csrfToken;
            res = await doRequest(csrfToken);
        }

        if (!res.ok) {
            const err = await res.json().catch(() => ({}));
            throw new Error(err?.error?.message || `${endpoint} failed`);
        }
        const json = await res.json();
        csrfTokenRef.current = csrfToken; // keep the working token cached
        return json.data as T;
    }

    // 鈹€鈹€鈹€ Stage handlers 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

    const runPlanner = useCallback(async (userInput?: string) => {
        setIsLoading(true);
        dispatch({ type: "SET_LOADING", stage: "planner" });
        try {
            const prompt = [
                `${input.destination}, ${input.startDate} to ${input.endDate}`,
                input.style ? `Style: ${input.style}` : "",
                userInput || "",
            ].filter(Boolean).join(". ");

            const data = await callApi<TripContext & { _meta: Parameters<typeof dispatch>[0] extends { meta: infer M } ? M : never }>("planner", { input: prompt });
            const { _meta, ...result } = data as { _meta: { durationMs: number; confidence: number; dataSources: string[]; decisionsLog: string[] } } & TripContext;
            dispatch({ type: "SET_PLANNER", result, meta: _meta });
        } catch (err) {
            dispatch({ type: "SET_ERROR", error: (err as Error).message });
            showToast("Planner agent failed. Try again.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [input, dispatch]);

    const runResearch = useCallback(async (plannerResult: TripContext, feedback?: string) => {
        setIsLoading(true);
        dispatch({ type: "SET_LOADING", stage: "research" });
        try {
            // Merge the user's original multi-vibe style (e.g. "relaxed, adventure") back into the
            // planner result before forwarding to research. The planner LLM only emits single-token
            // styles (its VALID_STYLES guard drops anything else), so without this merge the
            // downstream agents would only see whatever single style the LLM happened to infer.
            const mergedResult: TripContext = input.style
                ? { ...plannerResult, preferences: { ...plannerResult.preferences, style: input.style } }
                : plannerResult;
            const context = feedback
                ? { ...mergedResult, _feedback: feedback }
                : mergedResult;
            const data = await callApi<EnrichedTripContext & { _meta: { durationMs: number; confidence: number; dataSources: string[]; decisionsLog: string[] } }>("research", context);
            const { _meta, ...result } = data;
            dispatch({ type: "SET_RESEARCH", result, meta: _meta });
        } catch (err) {
            dispatch({ type: "SET_ERROR", error: (err as Error).message });
            showToast("Research agent failed. Try again.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [dispatch]);

    const runLogistics = useCallback(async (researchResult: EnrichedTripContext) => {
        setIsLoading(true);
        dispatch({ type: "SET_LOADING", stage: "logistics" });
        try {
            const data = await callApi<OptimizedTripContext & { _meta: { durationMs: number; confidence: number; dataSources: string[]; decisionsLog: string[] } }>("logistics", researchResult);
            const { _meta, ...result } = data;
            dispatch({ type: "SET_LOGISTICS", result, meta: _meta });
        } catch (err) {
            dispatch({ type: "SET_ERROR", error: (err as Error).message });
            showToast("Logistics agent failed. Try again.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [dispatch]);

    const runBudget = useCallback(async (logisticsResult: OptimizedTripContext) => {
        setIsLoading(true);
        dispatch({ type: "SET_LOADING", stage: "budget" });
        try {
            const data = await callApi<import("./types").BudgetedTripContext & { _meta: { durationMs: number; confidence: number; dataSources: string[]; decisionsLog: string[] } }>("budget", logisticsResult);
            const { _meta, ...result } = data;
            dispatch({ type: "SET_BUDGET", result, meta: _meta });
        } catch (err) {
            dispatch({ type: "SET_ERROR", error: (err as Error).message });
            showToast("Budget agent failed. Try again.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [dispatch]);

    const runSafety = useCallback(async (budgetResult: import("./types").BudgetedTripContext) => {
        setIsLoading(true);
        dispatch({ type: "SET_LOADING", stage: "safety" });
        try {
            const data = await callApi<import("./types").SafeTripContext & { _meta: { durationMs: number; confidence: number; dataSources: string[]; decisionsLog: string[] } }>("safety", budgetResult);
            const { _meta, ...result } = data;
            dispatch({ type: "SET_SAFETY", result, meta: _meta });
        } catch (err) {
            dispatch({ type: "SET_ERROR", error: (err as Error).message });
            showToast("Safety agent failed. Try again.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [dispatch]);

    const handleSave = useCallback(async () => {
        if (!state.safetyResult) return;
        setIsSaving(true);
        try {
            await callApi("save", { tripId, safetyResult: state.safetyResult });
            // Mark the session as completed 鈥?this synchronously clears localStorage
            // via the useFlowState effect, so the resume banner never appears after save.
            dispatch({ type: "SAVED" });
            // Confetti burst
            if (!prefersReduced) {
                confetti({ particleCount: 80, spread: 70, origin: { x: 0.2, y: 0.8 }, colors: ["#10B981", "#f59e0b", "#ffffff"] });
                confetti({ particleCount: 80, spread: 70, origin: { x: 0.8, y: 0.8 }, colors: ["#10B981", "#6366f1", "#ffffff"] });
            }
            showToast("Your trip is saved! Opening your itinerary...", "success");
            setTimeout(() => onComplete(tripId), 1800);
        } catch {
            showToast("Save failed. Check your connection and try again.", "error");
        } finally {
            setIsSaving(false);
        }
    }, [state.safetyResult, tripId, onComplete, prefersReduced, dispatch]);

    // Auto-start planner only after CSRF token is confirmed ready
    useEffect(() => {
        if (!csrfReady) return;
        if (!state.plannerResult && !isLoading && state.stage === "planner" && state.error === null) {
            runPlanner();
        }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [csrfReady]);

    function openExplain(stage: Exclude<FlowStage, "saved">) {
        setExplainStage(stage);
        setExplainOpen(true);
    }

    const activeExplainStage: Exclude<FlowStage, "saved"> = explainStage;

    // Don't render on server 鈥?portal needs document.body
    if (!mounted) return null;

    const overlay = (
        <div
            className="fixed inset-0 flex flex-col overflow-hidden"
            style={{
                zIndex: 9999,
                background:
                    "radial-gradient(ellipse 80% 55% at 15% 0%, rgba(99,102,241,0.10) 0%, transparent 60%)," +
                    "radial-gradient(ellipse 60% 45% at 85% 100%, rgba(168,85,247,0.07) 0%, transparent 50%)," +
                    "linear-gradient(180deg, #090C14 0%, #060810 100%)",
            }}
        >
            {/* Noise texture */}
            <div
                className="absolute inset-0 pointer-events-none opacity-[0.03] z-0"
                style={{
                    backgroundImage:
                        "url(\"data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E\")",
                }}
            />

            {/* 鈹€鈹€ System header (replaces old top bar) 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€ */}
            <SystemHeader state={state} isLoading={isLoading} onClose={onClose}>
                {/* Mobile-only pipeline header + DNA strip */}
                <div className="lg:hidden">
                    <AgentPipelineHeader
                        currentStage={state.stage}
                        meta={state.meta}
                        iteration={state.iteration}
                        onExplain={openExplain}
                        layout="horizontal"
                        imageUrl={state.input.imageUrl}
                        destination={state.input.destination}
                    />
                    <TripDNASummaryStrip state={state} />
                </div>
            </SystemHeader>

            {/* 鈹€鈹€ 3-Column Layout 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€ */}
            <div className="flex-1 overflow-hidden flow-layout relative z-10">
                {/* 鈹€鈹€ LEFT SIDEBAR 鈹€鈹€ Trip meta + vertical stepper 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€ */}
                <aside className="hidden lg:flex flex-col border-r border-white/[0.06] bg-[#0B0F19]/60 backdrop-blur-md overflow-y-auto flow-scroll">
                    {/* Trip DNA */}
                    <div className="px-4 pt-5 pb-3 border-b border-white/[0.06]">
                        <TripDNASummaryStrip state={state} layout="vertical" />
                    </div>

                    {/* Vertical pipeline stepper */}
                    <div className="flex-1 px-2 py-4">
                        <AgentPipelineHeader
                            currentStage={state.stage}
                            meta={state.meta}
                            iteration={state.iteration}
                            onExplain={openExplain}
                            layout="vertical"
                            imageUrl={state.input.imageUrl}
                            destination={state.input.destination}
                        />
                    </div>
                </aside>

                {/* 鈹€鈹€ CENTER 鈥?Main stage content 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€ */}
                <main className="flex-1 overflow-y-auto flow-scroll relative">
                    {/* Soft radial gradient behind center content */}
                    <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[800px] h-[600px] bg-gradient-to-b from-indigo-500/10 via-purple-500/5 to-transparent rounded-full blur-[100px] pointer-events-none opacity-50" />
                    
                    <div className="px-6 py-6 max-w-3xl mx-auto w-full relative z-10">
                        <AnimatePresence mode="wait">
                            <motion.div
                                key={state.stage}
                                variants={stageVariants}
                                initial={prefersReduced ? {} : "initial"}
                                animate="animate"
                                exit={prefersReduced ? {} : "exit"}
                                transition={stageTransition}
                            >
                                {/* Planner */}
                                {(state.stage === "planner") && (
                                    <PlannerStage
                                        input={flowInput}
                                        result={state.plannerResult}
                                        meta={state.meta.planner ?? null}
                                        isLoading={isLoading}
                                        error={state.error}
                                        onApprove={(result) => { dispatch({ type: "ADVANCE" }); runResearch(result); }}
                                        onAdjust={() => {}}
                                        onExplain={() => openExplain("planner")}
                                        onRetry={() => runPlanner()}
                                        onSubmitFeedback={(fb) => runPlanner(fb)}
                                    />
                                )}

                                {/* Research */}
                                {state.stage === "research" && (
                                    <ResearchStage
                                        input={flowInput}
                                        result={state.researchResult}
                                        meta={state.meta.research ?? null}
                                        isLoading={isLoading}
                                        error={state.error}
                                        onApprove={(result) => { dispatch({ type: "ADVANCE" }); runLogistics(result); }}
                                        onAdjust={() => {}}
                                        onExplain={() => openExplain("research")}
                                        onRetry={() => state.plannerResult && runResearch(state.plannerResult)}
                                        onSubmitFeedback={(fb) => state.plannerResult && runResearch(state.plannerResult, fb)}
                                    />
                                )}

                                {/* Logistics */}
                                {state.stage === "logistics" && (
                                    <LogisticsStage
                                        input={flowInput}
                                        result={state.logisticsResult}
                                        meta={state.meta.logistics ?? null}
                                        isLoading={isLoading}
                                        error={state.error}
                                        onApprove={(result) => { dispatch({ type: "ADVANCE" }); runBudget(result); }}
                                        onAdjust={() => {}}
                                        onExplain={() => openExplain("logistics")}
                                        onRetry={() => state.researchResult && runLogistics(state.researchResult)}
                                        onReoptimize={() => state.researchResult && runLogistics(state.researchResult)}
                                    />
                                )}

                                {/* Budget */}
                                {state.stage === "budget" && (
                                    <BudgetStage
                                        input={flowInput}
                                        result={state.budgetResult}
                                        meta={state.meta.budget ?? null}
                                        isLoading={isLoading}
                                        error={state.error}
                                        onApprove={(result) => { dispatch({ type: "ADVANCE" }); runSafety(result); }}
                                        onAdjust={() => state.researchResult && runLogistics(state.researchResult)}
                                        onExplain={() => openExplain("budget")}
                                        onRetry={() => state.logisticsResult && runBudget(state.logisticsResult)}
                                    />
                                )}

                                {/* Safety */}
                                {(state.stage === "safety" || state.stage === "saved") && (
                                    <SafetyStage
                                        input={flowInput}
                                        result={state.safetyResult}
                                        meta={state.meta.safety ?? null}
                                        isLoading={isLoading}
                                        error={state.error}
                                        onApprove={() => handleSave()}
                                        onAdjust={() => {}}
                                        onExplain={() => openExplain("safety")}
                                        onRetry={() => state.budgetResult && runSafety(state.budgetResult)}
                                        onSave={handleSave}
                                        onRedo={() => {
                                            resetAllAndRestart();
                                            showToast("Starting over 鈥?Run #" + (state.iteration + 1), "info");
                                            setTimeout(() => runPlanner(), 100);
                                        }}
                                        isSaving={isSaving}
                                    />
                                )}
                            </motion.div>
                        </AnimatePresence>
                    </div>
                </main>

                {/* 鈹€鈹€ RIGHT SIDEBAR 鈹€鈹€ Reasoning logs + AI suggestions 鈹€鈹€鈹€鈹€鈹€鈹€鈹€ */}
                <aside className="hidden lg:flex flex-col border-l border-white/[0.06] bg-[#080B13]/50 backdrop-blur-md overflow-hidden relative">
                    {/* Subtle purple glow behind reasoning panel */}
                    <div className="absolute top-1/4 right-0 w-[260px] h-[360px] bg-purple-500/[0.07] rounded-full blur-[70px] pointer-events-none" />
                    {/* Reasoning panel 鈥?cinematic agent log */}
                    <div className="flex-shrink-0 border-b border-white/[0.06] overflow-y-auto max-h-[310px] relative z-10">
                        <ReasoningPanel state={state} isLoading={isLoading} imageUrl={state.input.imageUrl} destination={state.input.destination} />
                    </div>
                    {/* AI suggestions panel below reasoning */}
                    <div className="flex-1 overflow-hidden relative z-10">
                        <AISuggestionsPanel state={state} isLoading={isLoading} />
                    </div>
                </aside>
            </div>

            {/* Offline banner */}
            <AnimatePresence>
                {isOffline && (
                    <motion.div
                        initial={{ opacity: 0, y: 8 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: 8 }}
                        className="fixed top-20 left-1/2 -translate-x-1/2 z-[60] flex items-center gap-2 bg-rose-500/10 border border-rose-500/30 rounded-2xl px-4 py-2.5 text-sm text-rose-400"
                    >
                        <WifiOff className="w-4 h-4" />
                        Check your connection and try again
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Toast */}
            <AnimatePresence>{toast && <Toast message={toast.message} variant={toast.variant} />}</AnimatePresence>

            {/* Explainability panel */}
            <ExplainabilityPanel
                isOpen={explainOpen}
                onClose={() => setExplainOpen(false)}
                stage={activeExplainStage}
                meta={state.meta[activeExplainStage] ?? null}
            />
        </div>
    );

    return createPortal(overlay, document.body);
}

