}

export function TripViewClient({ trip: initialTrip, rawItinerary: initialRaw, initialMessages }: TripViewClientProps) {
    const [trip, setTrip] = useState<TripDTO>(initialTrip);
    const [rawItinerary, setRawItinerary] = useState<Itinerary | null>(initialRaw);
    const [selectedDay, setSelectedDay] = useState<number | undefined>(undefined);
    const [focusedActivity, setFocusedActivity] = useState<ItineraryEvent | null>(null);
    const [eventOrder, setEventOrder] = useState<Record<number, string[]>>({});
    const [showMobileMap, setShowMobileMap] = useState(false);
    const [mounted, setMounted] = useState(false);

    // 鈹€鈹€ Refine Trip state 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    const [refineInput, setRefineInput] = useState("");
    const [isRefining, setIsRefining] = useState(false);
    const [refineError, setRefineError] = useState<string | null>(null);
    const [summaryOfChanges, setSummaryOfChanges] = useState<string | null>(null);

    // 鈹€鈹€ Risk analysis state 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    const [riskAnalysis, setRiskAnalysis] = useState<RiskAnalysisResult | null>(null);
    const [riskDismissed, setRiskDismissed] = useState(false);
    const [riskExpanded, setRiskExpanded] = useState(false);

    // 鈹€鈹€ Travel score state 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    const [travelScore, setTravelScore] = useState<TravelScoreResult | null>(null);

    // 鈹€鈹€ Explainability panel state 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    const [explainOpen, setExplainOpen] = useState(false);
    const [explainBullets, setExplainBullets] = useState<string[]>([]);

    // 鈹€鈹€ Offline state 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    const [isOffline, setIsOffline] = useState(false);

    // 鈹€鈹€ Export drawer state 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    const [showExportDrawer, setShowExportDrawer] = useState(false);

    // 鈹€鈹€ Landing-flow auto-launch 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    // When the user arrives from the hero "Create trip" 鈫?login flow, rawItinerary
    // is null (trip record exists, agents haven't run). We detect ?fromLanding=1
    // in the URL client-side (no Suspense needed 鈥?dynamic route, runs post-mount).
    const [showFlow, setShowFlow] = useState(false);
    const hasLaunchedFlowRef = useRef(false);
    // Style preference forwarded from the landing extraction 鈥?stored in a ref so
    // it's available synchronously when the overlay first renders.
    const flowStyleRef = useRef<string | undefined>(undefined);

    useEffect(() => {
        // eslint-disable-next-line react-hooks/set-state-in-effect
        setMounted(true);
    }, []);

    // Open the agent pipeline automatically when landing-flow context is present
    // and no itinerary has been generated yet. Fires exactly once per mount.
    useEffect(() => {
        if (initialRaw || hasLaunchedFlowRef.current) return;
        const params = new URLSearchParams(window.location.search);
        if (params.get("fromLanding") !== "1") return;
        flowStyleRef.current = params.get("style") ?? undefined;
        hasLaunchedFlowRef.current = true;
        // eslint-disable-next-line react-hooks/set-state-in-effect
        setShowFlow(true);
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    // Detect online/offline status and seed localStorage cache with initial data.
    useEffect(() => {
        // eslint-disable-next-line react-hooks/set-state-in-effect
        setIsOffline(!navigator.onLine);

        // Seed cache with server-provided data so it's available immediately offline.
        if (initialRaw) {
            try {
                localStorage.setItem(
                    `voyageai_trip_${initialTrip.id}`,
                    JSON.stringify({ ...initialTrip, rawItinerary: initialRaw })
                );
            } catch { /* storage quota 鈥?ignore */ }
        }

        const handleOnline  = () => setIsOffline(false);
        const handleOffline = () => setIsOffline(true);
        window.addEventListener("online",  handleOnline);
        window.addEventListener("offline", handleOffline);
        return () => {
            window.removeEventListener("online",  handleOnline);
            window.removeEventListener("offline", handleOffline);
        };
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    // Run risk analysis after itinerary loads / changes 鈥?non-blocking (post-render).
    useEffect(() => {
        if (!rawItinerary) {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setRiskAnalysis(null);
            return;
        }
        // eslint-disable-next-line react-hooks/set-state-in-effect
        setRiskDismissed(false);
        // eslint-disable-next-line react-hooks/set-state-in-effect
        setRiskAnalysis(analyzeTripRisks(rawItinerary, trip.budget.total));
        // eslint-disable-next-line react-hooks/set-state-in-effect
        setTravelScore(calculateTravelScore(rawItinerary, trip.budget.total));
    // trip.budget.total is a number 鈥?safe as dep
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [rawItinerary, trip.budget.total]);

    const handleEventsReorder = useCallback((dayNumber: number, orderedIds: string[]) => {
        setEventOrder((prev) => ({ ...prev, [dayNumber]: orderedIds }));
    }, []);

    const handleItineraryRefresh = useCallback(async () => {
        // Offline: load last cached trip from localStorage.
        if (!navigator.onLine) {
            try {
                const raw = localStorage.getItem(`voyageai_trip_${initialTrip.id}`);
                if (raw) {
                    const cached = JSON.parse(raw);
                    setTrip(cached as TripDTO);
                    setRawItinerary((cached?.rawItinerary as Itinerary) ?? null);
                }
            } catch { /* parse error 鈥?ignore */ }
            return;
        }

        try {
            const res = await fetch(`/api/trips/${initialTrip.id}`, { credentials: "include" });
            const json = await res.json();
            if (json?.success && json.data?.id && json.data?.budget) {
                setTrip(json.data as TripDTO);
                setRawItinerary((json.data?.rawItinerary as Itinerary) ?? null);
                // Cache for offline use.
                try {
                    localStorage.setItem(
                        `voyageai_trip_${initialTrip.id}`,
                        JSON.stringify(json.data)
                    );
                } catch { /* quota 鈥?ignore */ }
            }
        } catch {
            // silently ignore 鈥?user can reload
        }
    }, [initialTrip.id]);

    // 鈹€鈹€ Refine handler 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€
    const handleRefine = useCallback(
        async (e: React.FormEvent) => {
            e.preventDefault();
            if (!refineInput.trim() || !rawItinerary || isRefining) return;

            setIsRefining(true);
            setRefineError(null);
            setSummaryOfChanges(null);

            try {
                const csrf = await getCsrfToken();
                const res = await fetch("/api/ai/reoptimize", {
                    method: "POST",
                    credentials: "include",
                    headers: {
                        "Content-Type": "application/json",
                        ...(csrf ? { "x-csrf-token": csrf } : {}),
                    },
                    body: JSON.stringify({
                        tripId: initialTrip.id,
                        currentItinerary: rawItinerary,
                        reoptimizationReasons: ["preference_change"],
                        currentDay: selectedDay ?? 1,
                        remainingBudget: trip.budget.total,
                        modificationInstruction: refineInput.trim(),
                    }),
                });

                const json = await res.json();
                if (!json.success) {
                    throw new Error(json.error?.message ?? "Refinement failed. Please try again.");
