                                        </div>
                                    </div>
                                </Link>
                            </motion.div>
                        ))}
                    </AnimatePresence>
                ) }
            </div>
        </div>
    );
}

"use client";

import { useState, useMemo } from "react";
import { ChevronLeft, ChevronRight, MapPin } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import type { Trip } from "@/lib/api";

function getTripForDate(date: Date, trips: Trip[]): Trip | null {
    const y = date.getFullYear();
    const m = date.getMonth();
    const d = date.getDate();
    const ts = Date.UTC(y, m, d);
    for (const trip of trips) {
        const [sy, sm, sd] = trip.startDate.split("-").map(Number);
        const [ey, em, ed] = trip.endDate.split("-").map(Number);
        const start = Date.UTC(sy, sm - 1, sd);
        const end = Date.UTC(ey, em - 1, ed);
        if (ts >= start && ts <= end) return trip;
    }
    return null;
}

const MONTH_NAMES = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
const DAY_LABELS = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

function isDateInTripRanges(date: Date, trips: Trip[]): boolean {
    const y = date.getFullYear();
    const m = date.getMonth();
    const d = date.getDate();
    const ts = Date.UTC(y, m, d);
    for (const trip of trips) {
        const [sy, sm, sd] = trip.startDate.split("-").map(Number);
        const [ey, em, ed] = trip.endDate.split("-").map(Number);
        const start = Date.UTC(sy, sm - 1, sd);
        const end = Date.UTC(ey, em - 1, ed);
        if (ts >= start && ts <= end) return true;
    }
    return false;
}

function isDateStartOrEnd(date: Date, trips: Trip[]): boolean {
    const y = date.getFullYear();
    const m = date.getMonth();
    const d = date.getDate();
    const ds = `${y}-${String(m + 1).padStart(2, "0")}-${String(d).padStart(2, "0")}`;
    for (const trip of trips) {
        if (ds === trip.startDate || ds === trip.endDate) return true;
    }
    return false;
}

interface CalendarWidgetProps {
    trips: Trip[];
}

export function CalendarWidget({ trips }: CalendarWidgetProps) {
    const [viewDate, setViewDate] = useState(() => new Date());

    const { year, month, days, startOffset } = useMemo(() => {
        const y = viewDate.getFullYear();
        const m = viewDate.getMonth();
        const first = new Date(y, m, 1);
        const last = new Date(y, m + 1, 0);
        const startOffset = first.getDay();
        const totalDays = last.getDate();
        const days: { date: number; trip: Trip | null; isBoundary: boolean }[] = [];
        for (let d = 1; d <= totalDays; d++) {
            const cellDate = new Date(y, m, d);
            const trip = getTripForDate(cellDate, trips);
            days.push({
                date: d,
                trip,
                isBoundary: isDateStartOrEnd(cellDate, trips),
            });
        }
        return { year: y, month: m, days, startOffset };
    }, [viewDate, trips]);

    const [hoveredTrip, setHoveredTrip] = useState<{ trip: Trip; x: number; y: number } | null>(null);

    function prevMonth() {
        setViewDate((d: Date) => new Date(d.getFullYear(), d.getMonth() - 1));
    }

    function nextMonth() {
        setViewDate((d: Date) => new Date(d.getFullYear(), d.getMonth() + 1));
    }

    return (
        <div className="min-h-[320px] bg-white/[0.02] backdrop-blur-xl border border-white/5 rounded-[2rem] p-6 shadow-2xl relative overflow-hidden transition-all hover:border-white/10">
            <div className="flex items-center justify-between mb-6">
                <button
                    type="button"
                    onClick={prevMonth}
                    className="w-8 h-8 rounded-full flex items-center justify-center border border-white/5 hover:bg-white/5 transition-colors text-zinc-400 hover:text-white"
                >
                    <ChevronLeft className="w-4 h-4" />
                </button>
                <div className="text-white font-bold tracking-wide">
                    {MONTH_NAMES[month]} {year}
                </div>
                <button
                    type="button"
                    onClick={nextMonth}
                    className="w-8 h-8 rounded-full flex items-center justify-center border border-white/5 hover:bg-white/5 transition-colors text-zinc-400 hover:text-white"
                >
                    <ChevronRight className="w-4 h-4" />
                </button>
            </div>

            <div className="grid grid-cols-7 mb-4">
                {DAY_LABELS.map((day) => (
                    <div key={day} className="text-center text-[10px] font-bold uppercase tracking-wider text-zinc-500">
                        {day}
                    </div>
                ))}
            </div>

            <div className="grid grid-cols-7 gap-y-3">
                {[...Array(startOffset)].map((_, i) => (
                    <div key={`pad-${i}`} className="flex items-center justify-center" />
                ))}
                {days.map(({ date, trip, isBoundary }) => (
                    <div 
                        key={date} 
                        className="flex items-center justify-center relative"
                        onMouseEnter={(e) => {
                            if (trip) {
                                const rect = e.currentTarget.getBoundingClientRect();
                                setHoveredTrip({ trip, x: rect.left + rect.width / 2, y: rect.top });
                            }
                        }}
                        onMouseLeave={() => setHoveredTrip(null)}
                    >
                        <span
                            className={`w-8 h-8 flex items-center justify-center rounded-full text-xs font-semibold cursor-pointer transition-colors z-10 ${
                                isBoundary
                                    ? "bg-[#10B981] text-white shadow-[0_0_12px_rgba(16,185,129,0.25)]"
                                    : trip
                                        ? "bg-[#10B981]/20 text-[#10B981]"
                                        : "text-zinc-400 hover:bg-white/5 hover:text-white"
                            }`}
                        >
                            {date}
                        </span>
                    </div>
                ))}
            </div>

            <AnimatePresence>
                {hoveredTrip && (
                    <motion.div
                        initial={{ opacity: 0, y: 10, scale: 0.95 }}
                        animate={{ opacity: 1, y: -45, scale: 1 }}
                        exit={{ opacity: 0, y: 10, scale: 0.95 }}
                        className="fixed z-[100] pointer-events-none"
                        style={{ left: hoveredTrip.x, transform: "translateX(-50%)", top: hoveredTrip.y }}
                    >
                        <div className="bg-[#0B0F19] border border-white/10 rounded-xl px-3 py-2 shadow-2xl backdrop-blur-md flex items-center gap-2 whitespace-nowrap">
                            <div className="w-2 h-2 rounded-full bg-[#10B981] animate-pulse" />
                            <div className="flex flex-col">
                                <span className="text-[10px] uppercase font-bold text-zinc-500 tracking-wider leading-none mb-1">Upcoming Trip</span>
                                <span className="text-white text-xs font-bold flex items-center gap-1">
                                    <MapPin className="w-3 h-3 text-[#10B981]" />
                                    {hoveredTrip.trip.destination}
                                </span>
                            </div>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

import { useState } from "react";
import { Sparkles, Send, Loader2, CheckCircle2, Edit2, Check, X, Calendar, Wallet, Compass } from "lucide-react";
import { ensureCsrfToken, type Trip } from "@/lib/api";
import { motion, AnimatePresence } from "framer-motion";

interface DashboardAIAssistantProps {
    onTripCreated: (trip: Trip) => void;
}

interface RefinedTrip {
    destination: string;
    startDate?: string;
    endDate?: string;
    budget?: number;
    style?: string;
    raw: string;
}

export function DashboardAIAssistant({ onTripCreated }: DashboardAIAssistantProps) {
    const [prompt, setPrompt] = useState("");
    const [isLoading, setIsLoading] = useState(false);
    const [preview, setPreview] = useState<RefinedTrip | null>(null);
    const [successMsg, setSuccessMsg] = useState<string | null>(null);
    const [errorMsg, setErrorMsg] = useState<string | null>(null);

    const handleInitialSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!prompt.trim() || isLoading) return;

        setIsLoading(true);
        setErrorMsg(null);
        try {
            const csrf = await ensureCsrfToken();
            const res = await fetch("/api/ai/refine-trip", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "X-CSRF-Token": csrf,
                },
                body: JSON.stringify({ text: prompt }),
            });
            const data = await res.json();
            if (data.success && data.data) {
                setPreview(data.data);
            } else {
                throw new Error(data.message || "Failed to parse trip");
            }
        } catch (err) {
            setErrorMsg(err instanceof Error ? err.message : "AI failed to parse details");
        } finally {
            setIsLoading(false);
        }
    };

    const handleConfirm = async () => {
        if (!preview || isLoading) return;
        setIsLoading(true);
        try {
            const csrf = await ensureCsrfToken();
            const res = await fetch("/api/ai/create-trip", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "X-CSRF-Token": csrf,
                },
                body: JSON.stringify({ text: prompt }),
            });
            const data = await res.json();
            if (data.success) {
                onTripCreated(data.data);
                setSuccessMsg(`Adventure to ${data.data.destination} confirmed.`);
                setPreview(null);
                setPrompt("");
                setTimeout(() => setSuccessMsg(null), 5000);
            } else {
                throw new Error(data.message);
            }
        } catch (err) {
            setErrorMsg("Failed to create trip");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="bg-white/[0.02] backdrop-blur-xl border border-white/5 rounded-[2rem] p-6 relative overflow-hidden shadow-2xl transition-all hover:border-white/10 flex flex-col gap-4">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <Sparkles className="w-5 h-5 text-[#10B981]" />
                    <h2 className="text-xl font-bold text-white tracking-tight">AI Assistant</h2>
                </div>
                {preview && (
                    <span className="text-[10px] font-bold text-[#10B981] bg-[#10B981]/10 px-2 py-0.5 rounded-full uppercase">
                        Review Details
                    </span>
                )}
            </div>

            <AnimatePresence mode="wait">
                {preview ? (
                    <motion.div 
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        className="space-y-4"
                    >
                        <div className="grid grid-cols-2 gap-3">
                            <div className="p-3 rounded-xl bg-white/5 border border-white/5">
                                <span className="text-[10px] uppercase font-bold text-zinc-500 block mb-1">Destination</span>
                                <span className="text-sm font-bold text-white truncate block">{preview.destination}</span>
                            </div>
                            <div className="p-3 rounded-xl bg-white/5 border border-white/5">
                                <span className="text-[10px] uppercase font-bold text-zinc-500 block mb-1">Style</span>
                                <span className="text-sm font-bold text-[#10B981] truncate block">{preview.style ?? "Flexible"}</span>
                            </div>
                            <div className="p-3 rounded-xl bg-white/5 border border-white/5 col-span-2 flex items-center justify-between">
                                <div className="flex items-center gap-2">
                                    <Calendar className="w-3 h-3 text-zinc-500" />
                                    <span className="text-xs text-zinc-300 font-medium">
                                        {preview.startDate ? `${preview.startDate} 鈫?${preview.endDate}` : "TBD"}
                                    </span>
                                </div>
                                <div className="flex items-center gap-2 border-l border-white/10 pl-3">
                                    <Wallet className="w-3 h-3 text-zinc-500" />
                                    <span className="text-xs text-zinc-300 font-medium">
                                        {preview.budget ? `$${preview.budget.toLocaleString()}` : "Flexible"}
                                    </span>
                                </div>
                            </div>
                        </div>

                        <div className="flex items-center gap-2 pt-2">
                            <button
                                onClick={handleConfirm}
                                disabled={isLoading}
                                className="flex-1 bg-[#10B981] hover:bg-[#10B981]/90 text-black font-bold py-2 rounded-xl text-sm flex items-center justify-center gap-2 transition-all"
                            >
                                {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Check className="w-4 h-4" />}
                                Looks Perfect
                            </button>
                            <button
                                onClick={() => setPreview(null)}
                                disabled={isLoading}
                                className="p-2 rounded-xl bg-white/5 border border-white/5 text-zinc-400 hover:text-white transition-colors"
                                title="Edit Prompt"
                            >
                                <Edit2 className="w-4 h-4" />
                            </button>
                        </div>
                    </motion.div>
                ) : (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        className="space-y-4"
                    >
                        <p className="text-xs text-zinc-400">
                            Type natural language to instantly create a trip.
                        </p>
                        <form onSubmit={handleInitialSubmit} className="relative">
                            <textarea
                                value={prompt}
                                onChange={(e) => setPrompt(e.target.value)}
                                placeholder='e.g., "Trip to Bali, April 10-20, $1800 budget, relax vibes"'
                                className="w-full bg-black/20 border border-white/10 rounded-xl p-3 pr-12 text-sm text-white placeholder:text-zinc-600 focus:outline-none focus:border-[#10B981]/30 focus:ring-1 focus:ring-[#10B981]/20 resize-none h-24"
                                disabled={isLoading}
                            />
                            <button
                                type="submit"
                                disabled={!prompt.trim() || isLoading}
                                className="absolute bottom-3 right-3 p-2 rounded-lg bg-[#10B981]/10 text-[#10B981] hover:bg-[#10B981]/20 disabled:opacity-50 transition-colors"
                            >
                                {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
                            </button>
                        </form>
                    </motion.div>
                )}
            </AnimatePresence>

            {successMsg && (
                <div className="flex items-center gap-2 text-xs text-[#10B981] bg-[#10B981]/10 px-3 py-2 rounded-lg">
                    <CheckCircle2 className="w-4 h-4" />
                    {successMsg}
                </div>
            )}
            {errorMsg && (
                <div className="flex items-center gap-2 text-xs text-red-400 bg-red-400/10 px-3 py-2 rounded-lg">
                    <X className="w-4 h-4" />
                    {errorMsg}
                </div>
            )}
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Sparkles, ArrowRight, X } from "lucide-react";
import { loadFromStorage, clearStorage } from "../components/itinerary-flow/flowStorage";
import type { FlowState, FlowInput } from "../components/itinerary-flow/types";

// Only show the resume banner when the user has made meaningful progress.
// "planner" alone is trivial (< 5s to redo) and causes banner noise on every visit.
const MEANINGFUL_STAGES = new Set(["research", "logistics", "budget", "safety"]);

interface DashboardResumeBannerProps {
    onResume: (tripId: string, input: FlowInput) => void;
}

function readMeaningfulSession(): FlowState | null {
    const saved = loadFromStorage();
    if (!saved) return null;
    if (!MEANINGFUL_STAGES.has(saved.stage)) {
        // Not enough progress to be worth resuming 鈥?clean up silently.
        clearStorage();
        return null;
    }
    return saved;
}

export function DashboardResumeBanner({ onResume }: DashboardResumeBannerProps) {
    const [savedSession, setSavedSession] = useState<FlowState | null>(null);

    useEffect(() => {
        // Initial read on mount.
        setSavedSession(readMeaningfulSession());

        // Re-sync when the tab becomes visible again (e.g. after the flow completes
        // in a different context and clears localStorage).
        function handleVisibility() {
            if (document.visibilityState === "visible") {
                setSavedSession(readMeaningfulSession());
            }
        }
        document.addEventListener("visibilitychange", handleVisibility);
        return () => document.removeEventListener("visibilitychange", handleVisibility);
    }, []);

    const handleDismiss = (e: React.MouseEvent) => {
        e.preventDefault();
        e.stopPropagation();
        clearStorage();
        setSavedSession(null);
    };

    if (!savedSession) return null;

    return (
        <AnimatePresence>
            <motion.div
                initial={{ opacity: 0, y: -20, scale: 0.95 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                exit={{ opacity: 0, scale: 0.95 }}
                className="relative group"
            >
                <div className="absolute -inset-0.5 bg-gradient-to-r from-indigo-500 to-purple-600 rounded-2xl blur opacity-20 group-hover:opacity-40 transition duration-1000 group-hover:duration-200" />
                <div className="relative flex flex-col md:flex-row items-center justify-between gap-4 p-5 rounded-2xl bg-[#0B0F19]/80 backdrop-blur-xl border border-white/10 shadow-2xl overflow-hidden">
                    {/* Animated background flare */}
                    <div className="absolute top-0 right-0 -translate-y-1/2 translate-x-1/4 w-64 h-64 bg-indigo-500/10 rounded-full blur-[80px] pointer-events-none" />

                    <div className="flex items-center gap-4 relative z-10">
                        <div className="w-12 h-12 rounded-xl bg-indigo-500/20 border border-indigo-500/30 flex items-center justify-center text-indigo-400 shadow-[0_0_15px_rgba(99,102,241,0.2)]">
                            <Sparkles className="w-6 h-6" />
                        </div>
                        <div>
                            <h3 className="text-white font-bold text-base flex items-center gap-2">
                                Resume your planning session?
                                <span className="px-2 py-0.5 rounded-full bg-indigo-500/20 text-indigo-300 text-[10px] font-bold uppercase tracking-wider border border-indigo-500/30">
                                    Draft
                                </span>
                            </h3>
                            <p className="text-zinc-400 text-sm mt-0.5">
                                You were planning a trip to{" "}
                                <span className="text-indigo-300 font-semibold">
                                    {savedSession.input.destination}
                                </span>
                                . Pick up right where you left off.
                            </p>
                        </div>
                    </div>

                    <div className="flex items-center gap-3 relative z-10 w-full md:w-auto">
                        <button
                            onClick={() => onResume(savedSession.sessionId, savedSession.input)}
                            className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-2.5 rounded-xl bg-indigo-600 hover:bg-indigo-500 text-white text-sm font-semibold transition-all shadow-[0_0_20px_rgba(79,70,229,0.4)] hover:shadow-[0_0_30px_rgba(79,70,229,0.5)] group/btn"
                        >
                            Continue Planning
                            <ArrowRight className="w-4 h-4 group-hover/btn:translate-x-1 transition-transform" />
                        </button>
                        <button
                            onClick={handleDismiss}
                            className="p-2.5 rounded-xl bg-white/5 hover:bg-white/10 border border-white/10 text-zinc-400 hover:text-white transition-all"
                            title="Dismiss Draft"
                        >
                            <X className="w-5 h-5" />
                        </button>
                    </div>
                </div>
            </motion.div>
        </AnimatePresence>
    );
}

