"use client";

import React, { useState, useRef, useEffect } from "react";
import Link from "next/link";
import { Settings, LogOut, User } from "lucide-react";
import { DashboardSidebarFooter } from "./DashboardSidebarFooter";

interface MobileUserMenuProps {
    user: {
        name: string | null;
        image: string | null;
        email: string;
    };
}

export function MobileUserMenu({ user }: MobileUserMenuProps) {
    const [isOpen, setIsOpen] = useState(false);
    const menuRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    return (
        <div className="relative" ref={menuRef}>
            <button
                onClick={() => setIsOpen(!isOpen)}
                className={`w-10 h-10 rounded-full overflow-hidden shrink-0 focus:outline-none active:scale-90 transition-all duration-300 ring-2 ${isOpen ? 'ring-[#10B981] shadow-[0_0_15px_rgba(16,185,129,0.4)]' : 'ring-white/10 shadow-lg'}`}
            >
                {user.image ? (
                    <img src={user.image} alt={user.name ?? "User"} className="w-full h-full object-cover" />
                ) : (
                    <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-indigo-500 to-purple-600 text-white font-bold text-sm">
                        {user.name?.[0].toUpperCase() || "V"}
                    </div>
                )}
            </button>

            {isOpen && (
                <div className="absolute right-0 mt-3 w-60 bg-[#0B0F14]/90 backdrop-blur-3xl border border-white/10 rounded-[1.75rem] shadow-[0_20px_50px_rgba(0,0,0,0.6),0_0_1px_rgba(255,255,255,0.1)] overflow-hidden z-[100] animate-in fade-in zoom-in-95 slide-in-from-top-4 duration-300 ease-out">
                    {/* User Profile Info */}
                    <div className="px-5 py-4 border-b border-white/[0.05] bg-white/[0.02]">
                        <p className="text-sm font-bold text-white tracking-tight truncate">{user.name || "Traveller"}</p>
                        <p className="text-[11px] text-zinc-500 font-medium truncate mt-0.5">{user.email}</p>
                    </div>

                    {/* Menu Actions */}
                    <div className="p-1.5 space-y-0.5">
                        <Link
                            href="/dashboard/settings"
                            onClick={() => setIsOpen(false)}
                            className="flex items-center gap-3 px-3.5 py-2.5 rounded-[1.25rem] text-zinc-400 hover:text-white hover:bg-white/5 transition-all duration-200 group"
                        >
                            <div className="w-8 h-8 rounded-lg bg-zinc-800 flex items-center justify-center group-hover:bg-zinc-700 transition-colors shrink-0">
                                <Settings className="w-4 h-4" />
                            </div>
                            <span className="text-sm font-semibold tracking-wide">Settings</span>
                        </Link>

                        <DashboardSidebarFooter mobileMinimal />
                    </div>

                    <div className="h-0.5 w-full bg-gradient-to-r from-transparent via-[#10B981]/20 to-transparent opacity-50" />
                </div>
            )}
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import confetti from "canvas-confetti";
import { X, Loader2, Sparkles } from "lucide-react";
import { completeOnboarding, type OnboardPreferences } from "@/lib/api";
import { useAuthStore } from "@/stores/authStore";

const TRAVEL_STYLES = ["Adventure", "Culture", "Relaxation", "Foodie", "Luxury", "Budget", "Nature", "City"];
const PACE_OPTIONS = [
    { value: "slow" as const, label: "Slow & relaxed" },
    { value: "moderate" as const, label: "Balanced" },
    { value: "fast" as const, label: "Packed & active" },
];
const BUDGET_OPTIONS = [
    { value: "budget" as const, label: "Budget" },
    { value: "mid-range" as const, label: "Mid-range" },
    { value: "luxury" as const, label: "Luxury" },
];

function fireConfetti() {
    const count = 200;
    const defaults = { origin: { y: 0.7 }, zIndex: 9999 };
    function fire(particleRatio: number, opts: confetti.Options) {
        confetti({ ...defaults, ...opts, particleCount: Math.floor(count * particleRatio) });
    }
    fire(0.25, { spread: 26, startVelocity: 55 });
    fire(0.2, { spread: 60 });
    fire(0.35, { spread: 100, decay: 0.91, scalar: 0.8 });
    fire(0.1, { spread: 120, startVelocity: 25, decay: 0.92, scalar: 1.2 });
    fire(0.1, { spread: 120, startVelocity: 45 });
}

interface OnboardingModalProps {
    isOpen: boolean;
}

export function OnboardingModal({ isOpen }: OnboardingModalProps) {
    const { setOnboarded } = useAuthStore();
    const [travelStyles, setTravelStyles] = useState<string[]>([]);
    const [pacePreference, setPacePreference] = useState<"slow" | "moderate" | "fast">("moderate");
    const [budgetTier, setBudgetTier] = useState<"budget" | "mid-range" | "luxury">("mid-range");
    const [interests, setInterests] = useState<string[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [confettiFired, setConfettiFired] = useState(false);

    useEffect(() => {
        if (isOpen && !confettiFired) {
            fireConfetti();
            setConfettiFired(true);
        }
    }, [isOpen, confettiFired]);

    function toggleStyle(s: string) {
        setTravelStyles((prev) =>
            prev.includes(s) ? prev.filter((x) => x !== s) : prev.length < 5 ? [...prev, s] : prev
        );
    }

    async function handleSubmit(e: React.FormEvent) {
        e.preventDefault();
        setIsLoading(true);
        try {
            const prefs: OnboardPreferences = {
                travelStyles,
                pacePreference,
                budgetTier,
                interests: interests.length > 0 ? interests : undefined,
            };
            await completeOnboarding(prefs);
            setOnboarded();
        } catch {
            // keep modal open on error
        } finally {
            setIsLoading(false);
        }
    }

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[9998] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
            <div
                className="relative w-full max-w-lg bg-[#0B0F14] border border-white/10 rounded-2xl overflow-hidden shadow-2xl"
                onClick={(e) => e.stopPropagation()}
            >
                <div className="p-6 border-b border-white/5 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <Sparkles className="w-5 h-5 text-[#10B981]" />
                        <h2 className="text-xl font-bold text-white">Welcome! Set your preferences</h2>
                    </div>
                    <button
                        type="button"
                        onClick={() => {}}
                        className="w-8 h-8 rounded-full bg-white/5 hover:bg-white/10 flex items-center justify-center text-zinc-400"
                        disabled
                        aria-hidden
                    >
                        <X className="w-4 h-4" />
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="p-6 space-y-6">
                    <div>
                        <label className="block text-sm font-medium text-zinc-300 mb-2">Travel styles</label>
                        <div className="flex flex-wrap gap-2">
                            {TRAVEL_STYLES.map((s) => (
                                <button
                                    key={s}
                                    type="button"
                                    onClick={() => toggleStyle(s)}
                                    className={`px-3 py-1.5 rounded-full text-xs font-medium transition-all ${
                                        travelStyles.includes(s)
                                            ? "bg-[#10B981] text-white"
                                            : "bg-white/5 text-zinc-400 hover:bg-white/10 hover:text-white"
                                    }`}
                                >
                                    {s}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-zinc-300 mb-2">Pace</label>
                        <div className="flex gap-2">
                            {PACE_OPTIONS.map((o) => (
                                <button
                                    key={o.value}
                                    type="button"
                                    onClick={() => setPacePreference(o.value)}
                                    className={`flex-1 px-3 py-2 rounded-xl text-sm font-medium transition-all ${
                                        pacePreference === o.value
                                            ? "bg-[#10B981] text-white"
                                            : "bg-white/5 text-zinc-400 hover:bg-white/10 hover:text-white"
                                    }`}
                                >
                                    {o.label}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-zinc-300 mb-2">Budget tier</label>
                        <div className="flex gap-2">
                            {BUDGET_OPTIONS.map((o) => (
                                <button
                                    key={o.value}
                                    type="button"
                                    onClick={() => setBudgetTier(o.value)}
                                    className={`flex-1 px-3 py-2 rounded-xl text-sm font-medium transition-all ${
                                        budgetTier === o.value
                                            ? "bg-[#10B981] text-white"
                                            : "bg-white/5 text-zinc-400 hover:bg-white/10 hover:text-white"
                                    }`}
                                >
                                    {o.label}
                                </button>
                            ))}
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={isLoading}
                        className="w-full flex items-center justify-center gap-2 py-3 rounded-xl bg-[#10B981] hover:bg-[#10B981]/90 text-white font-semibold disabled:opacity-60"
                    >
                        {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : "Continue"}
                    </button>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { X, Sparkles, Loader2, AlertCircle } from "lucide-react";
import confetti from "canvas-confetti";
import { getCsrfToken } from "@/lib/api";

interface TravelDNAOnboardingModalProps {
    isOpen: boolean;
    onClose: () => void;
}

const BUDGET_RANGES = ["Budget ($)", "Moderate ($$)", "Luxury ($$$)"];
const TRAVEL_STYLES = ["Relaxing/Wellness", "Adventure/Outdoors", "Culture/History", "Food & Drink", "Nightlife"];
const TRAVEL_PACES = ["Slow/Relaxed", "Moderate", "Fast/Packed"];
const INTERESTS = ["Beaches", "Mountains", "Cities", "Nature", "Museums", "Shopping", "Festivals", "Architecture"];
const REGIONS = ["North America", "South America", "Europe", "Asia", "Africa", "Middle East", "Oceania"];

export function TravelDNAOnboardingModal({ isOpen, onClose }: TravelDNAOnboardingModalProps) {
    const [budget, setBudget] = useState(BUDGET_RANGES[1]);
    const [style, setStyle] = useState(TRAVEL_STYLES[0]);
    const [pace, setPace] = useState(TRAVEL_PACES[1]);
    const [selectedInterests, setSelectedInterests] = useState<string[]>([]);
    const [selectedRegions, setSelectedRegions] = useState<string[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (isOpen) {
            confetti({
                particleCount: 120,
                spread: 80,
                origin: { y: 0.6 },
                colors: ['#10B981', '#6366f1', '#ffffff']
            });
        }
    }, [isOpen]);

    if (!isOpen) return null;

    const toggleSelection = (item: string, list: string[], setList: (v: string[]) => void) => {
        if (list.includes(item)) {
            setList(list.filter(i => i !== item));
        } else {
            setList([...list, item]);
        }
    };

    async function handleSubmit() {
        setIsLoading(true);
        setError(null);

        const data = {
            budget,
            style,
            pace,
            interests: selectedInterests,
            regions: selectedRegions
        };

        try {
            const res = await fetch('/api/preferences', {
                method: 'POST',
                credentials: 'include',
                headers: {
                    'Content-Type': 'application/json',
                    'X-CSRF-Token': getCsrfToken(),
                },
                body: JSON.stringify({ data })
            });

            const result = await res.json();
            if (!result.success) {
                throw new Error(result.error?.message || "Failed to save preferences");
            }
            onClose();
        } catch (err) {
            setError(err instanceof Error ? err.message : "An unexpected error occurred.");
        } finally {
            setIsLoading(false);
        }
    }

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-md p-4">
            <div
                className="relative w-[95vw] md:w-full max-w-2xl bg-white/[0.06] backdrop-blur-xl border border-white/[0.1] rounded-3xl overflow-hidden shadow-[0_8px_32px_rgba(0,0,0,0.4),0_0_1px_rgba(255,255,255,0.1)] flex flex-col max-h-[90vh]"
                onClick={e => e.stopPropagation()}
            >
                {/* Header */}
                <div className="flex items-center justify-between p-6 border-b border-white/[0.06] relative bg-white/[0.02]">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-[#10B981]/15 flex items-center justify-center flex-shrink-0 border border-[#10B981]/20">
                            <Sparkles className="w-5 h-5 text-[#10B981]" />
                        </div>
                        <div>
                            <h2 className="text-xl font-bold text-white tracking-tight">Discover Your Travel DNA</h2>
                            <p className="text-xs text-slate-400">Tell us how you like to travel. We&apos;ll tailor everything.</p>
                        </div>
                    </div>
                </div>

                {/* Content */}
                <div className="p-6 overflow-y-auto space-y-6 hide-scrollbar">
                    {error && (
                        <div className="flex items-center gap-2.5 text-sm text-rose-400 bg-rose-500/10 border border-rose-500/20 rounded-xl px-4 py-3">
                            <AlertCircle className="w-4 h-4 flex-shrink-0" />
                            {error}
                        </div>
                    )}

                    <div className="space-y-6">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-semibold text-slate-300">Budget Range</label>
                                <select
                                    value={budget}
                                    onChange={e => setBudget(e.target.value)}
                                    disabled={isLoading}
                                    className="w-full bg-white/[0.04] backdrop-blur-sm border border-white/[0.08] hover:border-white/[0.12] focus:border-[#10B981]/50 focus:ring-1 focus:ring-[#10B981]/30 rounded-xl px-4 py-3 text-white outline-none transition-all duration-200 disabled:opacity-50 appearance-none"
                                >
                                    {BUDGET_RANGES.map(b => (
                                        <option key={b} value={b} className="bg-zinc-900 text-white">{b}</option>
                                    ))}
                                </select>
                            </div>

                            <div className="space-y-2">
                                <label className="text-sm font-semibold text-slate-300">Travel Style</label>
                                <select
                                    value={style}
                                    onChange={e => setStyle(e.target.value)}
                                    disabled={isLoading}
                                    className="w-full bg-white/[0.04] backdrop-blur-sm border border-white/[0.08] hover:border-white/[0.12] focus:border-[#10B981]/50 focus:ring-1 focus:ring-[#10B981]/30 rounded-xl px-4 py-3 text-white outline-none transition-all duration-200 disabled:opacity-50 appearance-none"
                                >
                                    {TRAVEL_STYLES.map(s => (
                                        <option key={s} value={s} className="bg-zinc-900 text-white">{s}</option>
                                    ))}
                                </select>
                            </div>

                            <div className="space-y-2">
                                <label className="text-sm font-semibold text-slate-300">Travel Pace</label>
                                <select
                                    value={pace}
                                    onChange={e => setPace(e.target.value)}
                                    disabled={isLoading}
                                    className="w-full bg-white/[0.04] backdrop-blur-sm border border-white/[0.08] hover:border-white/[0.12] focus:border-[#10B981]/50 focus:ring-1 focus:ring-[#10B981]/30 rounded-xl px-4 py-3 text-white outline-none transition-all duration-200 disabled:opacity-50 appearance-none"
                                >
                                    {TRAVEL_PACES.map(p => (
                                        <option key={p} value={p} className="bg-zinc-900 text-white">{p}</option>
                                    ))}
                                </select>
                            </div>
                        </div>

                        <div className="pt-2 space-y-3">
                            <label className="text-sm font-semibold text-slate-300">Interests</label>
                            <div className="flex flex-wrap gap-2">
                                {INTERESTS.map(interest => (
                                    <button
                                        key={interest}
                                        type="button"
                                        disabled={isLoading}
                                        onClick={() => toggleSelection(interest, selectedInterests, setSelectedInterests)}
                                        className={`px-3 py-1.5 rounded-full border text-xs font-medium transition-all duration-200 ease-out disabled:opacity-50 ${selectedInterests.includes(interest)
                                            ? "bg-[#10B981]/20 border-[#10B981]/50 text-[#10B981]"
                                            : "bg-white/[0.04] border-white/[0.08] text-slate-300 hover:bg-white/[0.08] hover:text-white"
                                            }`}
                                    >
                                        {interest}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="pt-2 space-y-3">
                            <label className="text-sm font-semibold text-slate-300">Preferred Regions</label>
                            <div className="flex flex-wrap gap-2">
                                {REGIONS.map(region => (
                                    <button
                                        key={region}
                                        type="button"
                                        disabled={isLoading}
                                        onClick={() => toggleSelection(region, selectedRegions, setSelectedRegions)}
                                        className={`px-3 py-1.5 rounded-full border text-xs font-medium transition-all duration-200 ease-out disabled:opacity-50 ${selectedRegions.includes(region)
                                            ? "bg-indigo-500/20 border-indigo-500/50 text-indigo-400"
                                            : "bg-white/[0.04] border-white/[0.08] text-slate-300 hover:bg-white/[0.08] hover:text-white"
                                            }`}
                                    >
                                        {region}
                                    </button>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>

                {/* Footer */}
                <div className="p-6 border-t border-white/[0.06] bg-white/[0.02] flex justify-end items-center">
                    <button
                        onClick={handleSubmit}
                        disabled={isLoading}
                        className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all duration-200 ease-out flex items-center gap-2 ${!isLoading
                            ? "bg-[#10B981] hover:bg-[#10B981]/90 text-zinc-900 shadow-[0_0_20px_rgba(16,185,129,0.3)] hover:scale-[1.02]"
                            : "bg-white/[0.04] text-slate-500 cursor-not-allowed"
                            }`}
                    >
                        {isLoading && <Loader2 className="w-4 h-4 animate-spin" />}
                        {isLoading ? "Saving Profile..." : "Complete Profile"}
                    </button>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect, useMemo } from "react";
import { Brain, Lightbulb, CalendarDays, Wallet, PlusCircle, Dna } from "lucide-react";
import { getCsrfToken, type Trip } from "@/lib/api";

// 鈹€鈹€鈹€ Types 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

interface DNAPreference {
