// 鈹€鈹€鈹€ Geocoding cache (module-level 鈥?persists across renders) 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

const GEO_CACHE_MAX = 100;
const geocodeCache = new Map<string, { lat: number; lng: number } | null>();

function normalizeGeoKey(name: string): string {
    return name.toLowerCase().trim();
}

function geocachePut(key: string, value: { lat: number; lng: number } | null): void {
    if (geocodeCache.size >= GEO_CACHE_MAX) {
        const oldest = geocodeCache.keys().next().value;
        if (oldest !== undefined) geocodeCache.delete(oldest);
    }
    geocodeCache.set(key, value);
}

async function geocodeLocation(
    query: string,
    token: string
): Promise<{ lat: number; lng: number } | null> {
    const key = normalizeGeoKey(query);
    if (geocodeCache.has(key)) return geocodeCache.get(key)!;
    try {
        const url = `https://api.mapbox.com/geocoding/v5/mapbox.places/${encodeURIComponent(key)}.json?access_token=${token}&limit=1`;
        const res = await fetch(url);
        if (!res.ok) { geocachePut(key, null); return null; }
        const data = await res.json() as { features?: Array<{ center: [number, number] }> };
        const center = data.features?.[0]?.center;
        if (
            center &&
            typeof center[0] === "number" && isFinite(center[0]) &&
            typeof center[1] === "number" && isFinite(center[1]) &&
            (center[0] !== 0 || center[1] !== 0)
        ) {
            const result = { lng: center[0], lat: center[1] };
            geocachePut(key, result);
            return result;
        }
        geocachePut(key, null);
        return null;
    } catch {
        geocachePut(key, null);
        return null;
    }
}

// 鈹€鈹€鈹€ Types 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

interface MapPoint {
    lng: number;
    lat: number;
    label: string;
    index: number;
}

interface TripMapProps {
    rawItinerary: Itinerary | null;
    selectedDay?: number;
    focusedActivity?: ItineraryEvent | null;
    eventOrder?: Record<number, string[]>;
}

// 鈹€鈹€鈹€ Helpers 鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€鈹€

function extractPoints(
    raw: Itinerary | null,
    selectedDay?: number,
    eventOrder?: Record<number, string[]>
): MapPoint[] {
    if (!raw?.days) return [];
    const days = selectedDay ? raw.days.filter((d) => d.day === selectedDay) : raw.days;

    const points: MapPoint[] = [];
    for (const day of days) {
        const order = eventOrder?.[day.day];
        const activities = order?.length
            ? [...day.activities].sort((a, b) => {
                const ai = order.indexOf(a.id);
                const bi = order.indexOf(b.id);
                return (ai === -1 ? 9999 : ai) - (bi === -1 ? 9999 : bi);
              })
            : day.activities;

        let idx = 0;
        for (const act of activities) {
            const lat = act.location?.lat;
            const lng = act.location?.lng;
            if (
                typeof lat === "number" && isFinite(lat) && lat !== 0 &&
                typeof lng === "number" && isFinite(lng) && lng !== 0
            ) {
                points.push({ lat, lng, label: act.name, index: idx });
            }
            idx++;
        }
    }
    return points;
}

